  ];
  business_prefixes TEXT[] := ARRAY[
    'Il Nuovo', 'La Moderna', 'Antica', 'Il Miglior', 'La Perfetta', 'Nuova', 'Il Professionista',
    'La Grande', 'Il Centro', 'La Casa', 'Il Punto', 'La Bottega', 'Il Negozio', 'La Stanza',
