-- FILE: 20260326103942_add_services_description_to_business_locations.sql
-- ============================================================
/*
  # Add services_description field to business_locations

  1. Changes
    - Add `services_description` text field to `business_locations` table
    - This field will store a free-form text description of services offered at each location
    - Similar to the description field, but specifically for services
    - No formatting constraints - users can write services however they want

  2. Notes
    - Field is nullable to support existing locations
    - Stored as plain text for maximum flexibility
    - Can be edited by business owners and admins
*/

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'business_locations' AND column_name = 'services_description'
  ) THEN
    ALTER TABLE business_locations 
    ADD COLUMN services_description text;
  END IF;
END $$;


-- ============================================================
-- FILE: 20260326105300_create_admin_delete_user_function.sql
-- ============================================================
/*
  # Create Admin Delete User Function

  1. Changes
    - Create function `admin_delete_user_account(user_id_to_delete uuid)` that allows admins to delete any user
    - Similar to `delete_user_account()` but accepts a user ID parameter
    - Only executable by admins (checked via RLS and is_admin field)

  2. Security
    - Function checks if caller is admin before proceeding
    - SECURITY DEFINER to allow deletion of data
    - Comprehensive cleanup of all user data and relationships
*/

CREATE OR REPLACE FUNCTION admin_delete_user_account(user_id_to_delete uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  caller_user_id uuid;
  is_caller_admin boolean;
  user_business_id uuid;
  user_fiscal_code text;
  family_fiscal_codes text[];
  family_member_ids uuid[];
BEGIN
  -- Ottieni l'ID dell'utente che sta chiamando la funzione
  caller_user_id := auth.uid();
  
  IF caller_user_id IS NULL THEN
    RAISE EXCEPTION 'Non autenticato';
  END IF;

  -- Verifica che il chiamante sia un admin
  SELECT is_admin INTO is_caller_admin
  FROM profiles
  WHERE id = caller_user_id;

  IF NOT COALESCE(is_caller_admin, false) THEN
    RAISE EXCEPTION 'Permesso negato: solo gli admin possono eliminare gli utenti';
  END IF;

  -- Verifica che l'utente da eliminare esista
  IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = user_id_to_delete) THEN
    RAISE EXCEPTION 'Utente non trovato';
  END IF;

  -- Ottieni l'ID del business se l'utente è un business (cerca tramite owner_id)
  SELECT id INTO user_business_id
  FROM businesses
  WHERE owner_id = user_id_to_delete;

  -- Ottieni il codice fiscale dell'utente
  SELECT fiscal_code INTO user_fiscal_code
  FROM profiles
  WHERE id = user_id_to_delete;

  -- Ottieni i codici fiscali dei membri della famiglia
  SELECT array_agg(fiscal_code)
  INTO family_fiscal_codes
  FROM customer_family_members
  WHERE customer_id = user_id_to_delete
    AND fiscal_code IS NOT NULL
    AND fiscal_code != '';

  -- Ottieni gli ID dei membri della famiglia
  SELECT array_agg(id)
  INTO family_member_ids
  FROM customer_family_members
  WHERE customer_id = user_id_to_delete;

  -- ========================================
  -- GESTIONE RIFERIMENTI CHE DEVONO RESTARE
  -- ========================================
  
  -- Gestisci le recensioni approvate da questo utente (mantieni la review ma rimuovi il riferimento all'admin)
  UPDATE reviews SET approved_by = NULL WHERE approved_by = user_id_to_delete;

  -- Gestisci i report revisionati da questo utente (mantieni il report ma rimuovi il riferimento all'admin)
  UPDATE reports SET reviewed_by = NULL WHERE reviewed_by = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE CONTENUTI UTENTE CUSTOMER
  -- ========================================

  -- Elimina i preferiti dell'utente
  DELETE FROM favorite_businesses WHERE user_id = user_id_to_delete;
  DELETE FROM favorite_classified_ads WHERE user_id = user_id_to_delete;
  DELETE FROM favorite_job_postings WHERE user_id = user_id_to_delete;

  -- Elimina le redemptions degli sconti dell'utente
  DELETE FROM discount_redemptions WHERE customer_id = user_id_to_delete;

  -- Elimina TUTTE le recensioni dell'utente (proprie e dei membri della famiglia)
  DELETE FROM reviews WHERE customer_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM reviews WHERE family_member_id = ANY(family_member_ids);
  END IF;

  -- Elimina TUTTI gli annunci classificati (propri e dei membri della famiglia)
  DELETE FROM classified_ads WHERE user_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM classified_ads WHERE family_member_id = ANY(family_member_ids);
  END IF;

  -- Elimina le visualizzazioni degli annunci classificati
  DELETE FROM classified_ad_views WHERE user_id = user_id_to_delete;

  -- Elimina l'attività utente e i log
  DELETE FROM user_activity WHERE user_id = user_id_to_delete;
  DELETE FROM activity_log WHERE user_id = user_id_to_delete;
  
  -- Elimina i rewards
  DELETE FROM user_rewards WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE CONTENUTI BUSINESS
  -- ========================================

  IF user_business_id IS NOT NULL THEN
    -- Elimina le risposte alle recensioni del business
    DELETE FROM review_responses WHERE business_id = user_business_id;
    
    -- Elimina le visualizzazioni degli annunci di lavoro
    DELETE FROM job_views WHERE job_posting_id IN (
      SELECT id FROM job_postings WHERE business_id = user_business_id
    );
    
    -- Elimina le application agli annunci di lavoro
    DELETE FROM job_applications WHERE job_posting_id IN (
      SELECT id FROM job_postings WHERE business_id = user_business_id
    );
    
    -- Elimina i prodotti dell'azienda
    DELETE FROM products WHERE business_id = user_business_id;
    
    -- Elimina gli annunci di lavoro
    DELETE FROM job_postings WHERE business_id = user_business_id;
    
    -- Elimina gli sconti
    DELETE FROM discounts WHERE business_id = user_business_id;
    
    -- Elimina le sedi aziendali
    DELETE FROM business_locations WHERE business_id = user_business_id;
    
    -- Elimina il business
    DELETE FROM businesses WHERE id = user_business_id;
  END IF;

  -- Elimina le attività registrate (dalla tabella registered_businesses)
  DELETE FROM registered_business_locations WHERE business_id IN (
    SELECT id FROM registered_businesses WHERE owner_id = user_id_to_delete
  );
  DELETE FROM registered_businesses WHERE owner_id = user_id_to_delete;

  -- Elimina le attività aggiunte dall'utente (ma non ancora registrate)
  DELETE FROM unclaimed_business_locations WHERE added_by = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE JOB SEEKING
  -- ========================================

  -- Elimina le richieste di lavoro (proprie e dei membri della famiglia)
  DELETE FROM job_requests WHERE customer_id = user_id_to_delete;
  
  -- Elimina gli annunci job seeker dell'utente E dei membri della famiglia
  DELETE FROM job_seekers WHERE user_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM job_seekers WHERE family_member_id = ANY(family_member_ids);
  END IF;
  
  -- Elimina le application inviate dall'utente
  DELETE FROM job_applications WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE MESSAGGI (SISTEMA UNIFICATO)
  -- ========================================

  -- Elimina i messaggi inviati dall'utente
  DELETE FROM messages WHERE sender_id = user_id_to_delete;
  
  -- Elimina le conversazioni dove l'utente è partecipante (o i suoi familiari)
  DELETE FROM conversations WHERE 
    participant1_id = user_id_to_delete
    OR participant2_id = user_id_to_delete;
  
  -- Elimina conversazioni dei membri della famiglia
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM conversations WHERE 
      participant1_family_member_id = ANY(family_member_ids)
      OR participant2_family_member_id = ANY(family_member_ids);
  END IF;

  -- ========================================
  -- ELIMINAZIONE SEGNALAZIONI E NOTIFICHE
  -- ========================================

  -- Elimina le segnalazioni fatte dall'utente
  DELETE FROM reports WHERE reporter_id = user_id_to_delete;

  -- Elimina le notifiche
  DELETE FROM notifications WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE ABBONAMENTI E FAMIGLIA
  -- ========================================

  -- Elimina gli abbonamenti
  DELETE FROM subscriptions WHERE customer_id = user_id_to_delete;

  -- Elimina i membri della famiglia
  DELETE FROM customer_family_members WHERE customer_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE TRIAL HISTORY
  -- ========================================

  -- Rimuovi il codice fiscale del titolare dalla trial history
  IF user_fiscal_code IS NOT NULL AND user_fiscal_code != '' THEN
    DELETE FROM trial_usage_history WHERE fiscal_code = user_fiscal_code;
  END IF;

  -- Rimuovi i codici fiscali dei membri della famiglia dalla trial history
  IF family_fiscal_codes IS NOT NULL AND array_length(family_fiscal_codes, 1) > 0 THEN
    DELETE FROM trial_usage_history WHERE fiscal_code = ANY(family_fiscal_codes);
  END IF;

  -- ========================================
  -- ELIMINAZIONE PROFILO E ACCOUNT AUTH
  -- ========================================

  -- Elimina il profilo
  DELETE FROM profiles WHERE id = user_id_to_delete;

  -- Elimina l'utente auth
  DELETE FROM auth.users WHERE id = user_id_to_delete;

  RAISE NOTICE 'Account eliminato completamente dall''admin %: %', caller_user_id, user_id_to_delete;

END;
$$;

-- Permetti solo agli admin di eseguire questa funzione
GRANT EXECUTE ON FUNCTION admin_delete_user_account(uuid) TO authenticated;

-- Commento sulla funzione
COMMENT ON FUNCTION admin_delete_user_account(uuid) IS 'Permette agli admin di eliminare completamente qualsiasi account utente. Eliminazione PERMANENTE e IRREVERSIBILE.';


-- ============================================================
-- FILE: 20260326110026_fix_admin_delete_user_remove_products.sql
-- ============================================================
/*
  # Fix Admin Delete User - Remove Products Reference

  1. Problem
    - Function tries to delete from products table using business_id column
    - Products table doesn't have business_id column
    - Products are standalone entities not linked to businesses

  2. Solution
    - Remove the DELETE FROM products line from the function
*/

CREATE OR REPLACE FUNCTION admin_delete_user_account(user_id_to_delete uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  caller_user_id uuid;
  is_caller_admin boolean;
  user_business_id uuid;
  user_fiscal_code text;
  family_fiscal_codes text[];
  family_member_ids uuid[];
BEGIN
  -- Ottieni l'ID dell'utente che sta chiamando la funzione
  caller_user_id := auth.uid();
  
  IF caller_user_id IS NULL THEN
    RAISE EXCEPTION 'Non autenticato';
  END IF;

  -- Verifica che il chiamante sia un admin
  SELECT is_admin INTO is_caller_admin
  FROM profiles
  WHERE id = caller_user_id;

  IF NOT COALESCE(is_caller_admin, false) THEN
    RAISE EXCEPTION 'Permesso negato: solo gli admin possono eliminare gli utenti';
  END IF;

  -- Verifica che l'utente da eliminare esista
  IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = user_id_to_delete) THEN
    RAISE EXCEPTION 'Utente non trovato';
  END IF;

  -- Ottieni l'ID del business se l'utente è un business (cerca tramite owner_id)
  SELECT id INTO user_business_id
  FROM businesses
  WHERE owner_id = user_id_to_delete;

  -- Ottieni il codice fiscale dell'utente
  SELECT fiscal_code INTO user_fiscal_code
  FROM profiles
  WHERE id = user_id_to_delete;

  -- Ottieni i codici fiscali dei membri della famiglia
  SELECT array_agg(fiscal_code)
  INTO family_fiscal_codes
  FROM customer_family_members
  WHERE customer_id = user_id_to_delete
    AND fiscal_code IS NOT NULL
    AND fiscal_code != '';

  -- Ottieni gli ID dei membri della famiglia
  SELECT array_agg(id)
  INTO family_member_ids
  FROM customer_family_members
  WHERE customer_id = user_id_to_delete;

  -- ========================================
  -- GESTIONE RIFERIMENTI CHE DEVONO RESTARE
  -- ========================================
  
  -- Gestisci le recensioni approvate da questo utente (mantieni la review ma rimuovi il riferimento all'admin)
  UPDATE reviews SET approved_by = NULL WHERE approved_by = user_id_to_delete;

  -- Gestisci i report revisionati da questo utente (mantieni il report ma rimuovi il riferimento all'admin)
  UPDATE reports SET reviewed_by = NULL WHERE reviewed_by = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE CONTENUTI UTENTE CUSTOMER
  -- ========================================

  -- Elimina i preferiti dell'utente
  DELETE FROM favorite_businesses WHERE user_id = user_id_to_delete;
  DELETE FROM favorite_classified_ads WHERE user_id = user_id_to_delete;
  DELETE FROM favorite_job_postings WHERE user_id = user_id_to_delete;

  -- Elimina le redemptions degli sconti dell'utente
  DELETE FROM discount_redemptions WHERE customer_id = user_id_to_delete;

  -- Elimina TUTTE le recensioni dell'utente (proprie e dei membri della famiglia)
  DELETE FROM reviews WHERE customer_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM reviews WHERE family_member_id = ANY(family_member_ids);
  END IF;

  -- Elimina TUTTI gli annunci classificati (propri e dei membri della famiglia)
  DELETE FROM classified_ads WHERE user_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM classified_ads WHERE family_member_id = ANY(family_member_ids);
  END IF;

  -- Elimina le visualizzazioni degli annunci classificati
  DELETE FROM classified_ad_views WHERE user_id = user_id_to_delete;

  -- Elimina l'attività utente e i log
  DELETE FROM user_activity WHERE user_id = user_id_to_delete;
  DELETE FROM activity_log WHERE user_id = user_id_to_delete;
  
  -- Elimina i rewards
  DELETE FROM user_rewards WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE CONTENUTI BUSINESS
  -- ========================================

  IF user_business_id IS NOT NULL THEN
    -- Elimina le risposte alle recensioni del business
    DELETE FROM review_responses WHERE business_id = user_business_id;
    
    -- Elimina le visualizzazioni degli annunci di lavoro
    DELETE FROM job_views WHERE job_posting_id IN (
      SELECT id FROM job_postings WHERE business_id = user_business_id
    );
    
    -- Elimina le application agli annunci di lavoro
    DELETE FROM job_applications WHERE job_posting_id IN (
      SELECT id FROM job_postings WHERE business_id = user_business_id
    );
    
    -- Elimina gli annunci di lavoro
    DELETE FROM job_postings WHERE business_id = user_business_id;
    
    -- Elimina gli sconti
    DELETE FROM discounts WHERE business_id = user_business_id;
    
    -- Elimina le sedi aziendali
    DELETE FROM business_locations WHERE business_id = user_business_id;
    
    -- Elimina il business
    DELETE FROM businesses WHERE id = user_business_id;
  END IF;

  -- Elimina le attività registrate (dalla tabella registered_businesses)
  DELETE FROM registered_business_locations WHERE business_id IN (
    SELECT id FROM registered_businesses WHERE owner_id = user_id_to_delete
  );
  DELETE FROM registered_businesses WHERE owner_id = user_id_to_delete;

  -- Elimina le attività aggiunte dall'utente (ma non ancora registrate)
  DELETE FROM unclaimed_business_locations WHERE added_by = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE JOB SEEKING
  -- ========================================

  -- Elimina le richieste di lavoro (proprie e dei membri della famiglia)
  DELETE FROM job_requests WHERE customer_id = user_id_to_delete;
  
  -- Elimina gli annunci job seeker dell'utente E dei membri della famiglia
  DELETE FROM job_seekers WHERE user_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM job_seekers WHERE family_member_id = ANY(family_member_ids);
  END IF;
  
  -- Elimina le application inviate dall'utente
  DELETE FROM job_applications WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE MESSAGGI (SISTEMA UNIFICATO)
  -- ========================================

  -- Elimina i messaggi inviati dall'utente
  DELETE FROM messages WHERE sender_id = user_id_to_delete;
  
  -- Elimina le conversazioni dove l'utente è partecipante (o i suoi familiari)
  DELETE FROM conversations WHERE 
    participant1_id = user_id_to_delete
    OR participant2_id = user_id_to_delete;
  
  -- Elimina conversazioni dei membri della famiglia
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM conversations WHERE 
      participant1_family_member_id = ANY(family_member_ids)
      OR participant2_family_member_id = ANY(family_member_ids);
  END IF;

  -- ========================================
  -- ELIMINAZIONE SEGNALAZIONI E NOTIFICHE
  -- ========================================

  -- Elimina le segnalazioni fatte dall'utente
  DELETE FROM reports WHERE reporter_id = user_id_to_delete;

  -- Elimina le notifiche
  DELETE FROM notifications WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE ABBONAMENTI E FAMIGLIA
  -- ========================================

  -- Elimina gli abbonamenti
  DELETE FROM subscriptions WHERE customer_id = user_id_to_delete;

  -- Elimina i membri della famiglia
  DELETE FROM customer_family_members WHERE customer_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE TRIAL HISTORY
  -- ========================================

  -- Rimuovi il codice fiscale del titolare dalla trial history
  IF user_fiscal_code IS NOT NULL AND user_fiscal_code != '' THEN
    DELETE FROM trial_usage_history WHERE fiscal_code = user_fiscal_code;
  END IF;

  -- Rimuovi i codici fiscali dei membri della famiglia dalla trial history
  IF family_fiscal_codes IS NOT NULL AND array_length(family_fiscal_codes, 1) > 0 THEN
    DELETE FROM trial_usage_history WHERE fiscal_code = ANY(family_fiscal_codes);
  END IF;

  -- ========================================
  -- ELIMINAZIONE PROFILO E ACCOUNT AUTH
  -- ========================================

  -- Elimina il profilo
  DELETE FROM profiles WHERE id = user_id_to_delete;

  -- Elimina l'utente auth
  DELETE FROM auth.users WHERE id = user_id_to_delete;

  RAISE NOTICE 'Account eliminato completamente dall''admin %: %', caller_user_id, user_id_to_delete;

END;
$$;

-- Permetti solo agli admin di eseguire questa funzione
GRANT EXECUTE ON FUNCTION admin_delete_user_account(uuid) TO authenticated;

-- Commento sulla funzione
COMMENT ON FUNCTION admin_delete_user_account(uuid) IS 'Permette agli admin di eliminare completamente qualsiasi account utente. Eliminazione PERMANENTE e IRREVERSIBILE.';


-- ============================================================
-- FILE: 20260326110835_fix_subscription_type_save_plan_name.sql
-- ============================================================
/*
  # Fix Subscription Type - Salva Nome Piano Completo
  
  1. Problema Risolto
    - Il campo subscription_type salvava solo "monthly" o "annual"
    - Causava confusione tra piani business e customer nel pannello admin
    
  2. Soluzione
    - Aggiorna i trigger per salvare il nome completo del piano
    - Aggiunge il sync automatico del subscription_type quando viene creato/aggiornato un abbonamento
    
  3. Note
    - Funziona sia per customer che per business
    - Il nome del piano viene preso dalla tabella subscription_plans
*/

-- Funzione per sincronizzare subscription_type con il piano selezionato
CREATE OR REPLACE FUNCTION public.sync_subscription_type_from_plan()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  plan_name text;
BEGIN
  -- Ottieni il nome del piano
  SELECT name INTO plan_name
  FROM subscription_plans
  WHERE id = NEW.plan_id;
  
  -- Aggiorna il profilo con il nome del piano
  IF plan_name IS NOT NULL THEN
    UPDATE profiles
    SET 
      subscription_type = plan_name,
      subscription_status = NEW.status
    WHERE id = NEW.customer_id;
  END IF;
  
  RETURN NEW;
END;
$$;

-- Elimina trigger esistente se presente
DROP TRIGGER IF EXISTS trigger_sync_subscription_type ON subscriptions;

-- Crea trigger per sincronizzare subscription_type
CREATE TRIGGER trigger_sync_subscription_type
  AFTER INSERT OR UPDATE ON subscriptions
  FOR EACH ROW
  WHEN (NEW.status IN ('active', 'trial'))
  EXECUTE FUNCTION sync_subscription_type_from_plan();

-- Aggiorna la funzione trial per customer
CREATE OR REPLACE FUNCTION public.create_trial_for_customer()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  base_plan_id uuid;
  base_plan_name text;
BEGIN
  -- Solo per utenti customer, non per business o admin
  IF NEW.user_type != 'customer' THEN
    RETURN NEW;
  END IF;

  -- Ottieni l'ID e il nome del piano base (1 persona, mensile, più economico, NON business)
  SELECT id, name INTO base_plan_id, base_plan_name
  FROM subscription_plans
  WHERE max_persons = 1 
    AND billing_period = 'monthly'
    AND name NOT LIKE '%Business%'
  ORDER BY price ASC
  LIMIT 1;

  -- Se non troviamo il piano, usa il primo piano disponibile non business
  IF base_plan_id IS NULL THEN
    SELECT id, name INTO base_plan_id, base_plan_name
    FROM subscription_plans
    WHERE name NOT LIKE '%Business%'
    ORDER BY price ASC
    LIMIT 1;
  END IF;

  -- Crea l'abbonamento trial solo se esiste un piano e non ci sono già abbonamenti
  IF base_plan_id IS NOT NULL THEN
    INSERT INTO subscriptions (
      customer_id,
      plan_id,
      status,
      start_date,
      end_date,
      trial_end_date,
      payment_method_added,
      reminder_sent
    )
    VALUES (
      NEW.id,
      base_plan_id,
      'trial',
      NOW(),
      NOW() + INTERVAL '30 days',
      NOW() + INTERVAL '30 days',
      false,
      false
    )
    ON CONFLICT DO NOTHING;
    
    -- Aggiorna il profilo con il nome del piano e lo status trial
    UPDATE profiles
    SET 
      subscription_type = base_plan_name,
      subscription_status = 'trial',
      subscription_expires_at = NOW() + INTERVAL '30 days'
    WHERE id = NEW.id;
  END IF;

  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    -- Non bloccare la registrazione se c'è un errore
    RETURN NEW;
END;
$$;

-- Aggiorna la funzione trial per business
CREATE OR REPLACE FUNCTION public.create_trial_for_business()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  base_plan_id uuid;
  base_plan_name text;
BEGIN
  -- Solo per utenti business, non per customer o admin
  IF NEW.user_type != 'business' THEN
    RETURN NEW;
  END IF;

  -- Ottieni l'ID e il nome del piano base business (1 sede, mensile, più economico)
  SELECT id, name INTO base_plan_id, base_plan_name
  FROM subscription_plans
  WHERE max_persons = 1 
    AND billing_period = 'monthly'
    AND name LIKE '%Business%'
  ORDER BY price ASC
  LIMIT 1;

  -- Se non troviamo il piano, usa il primo piano business disponibile
  IF base_plan_id IS NULL THEN
    SELECT id, name INTO base_plan_id, base_plan_name
    FROM subscription_plans
    WHERE name LIKE '%Business%'
    ORDER BY price ASC
    LIMIT 1;
  END IF;

  -- Crea l'abbonamento trial solo se esiste un piano e non ci sono già abbonamenti
  IF base_plan_id IS NOT NULL THEN
    INSERT INTO subscriptions (
      customer_id,
      plan_id,
      status,
      start_date,
      end_date,
      trial_end_date,
      payment_method_added,
      reminder_sent
    )
    VALUES (
      NEW.id,
      base_plan_id,
      'trial',
      NOW(),
      NOW() + INTERVAL '30 days',
      NOW() + INTERVAL '30 days',
      false,
      false
    )
    ON CONFLICT DO NOTHING;
    
    -- Aggiorna il profilo con il nome del piano e lo status trial
    UPDATE profiles
    SET 
      subscription_type = base_plan_name,
      subscription_status = 'trial',
      subscription_expires_at = NOW() + INTERVAL '30 days'
    WHERE id = NEW.id;
  END IF;

  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    -- Non bloccare la registrazione se c'è un errore
    RETURN NEW;
END;
$$;


-- ============================================================
-- FILE: 20260326111850_fix_subscription_deletion_for_admin_cleanup.sql
-- ============================================================
/*
  # Fix Eliminazione Abbonamenti per Admin
  
  1. Problema
    - Il trigger `prevent_trial_plan_changes` blocca la DELETE anche quando chiamata da admin
    - Gli abbonamenti non vengono eliminati quando l'admin cancella un utente
    
  2. Soluzione
    - Modifica il trigger per permettere DELETE se chiamata nel contesto SECURITY DEFINER
    - Gli admin possono eliminare abbonamenti anche in trial
    
  3. Note
    - La funzione admin_delete_user_account ora può eliminare correttamente gli abbonamenti
    - Il trigger protegge ancora gli utenti normali dal cancellare abbonamenti trial
*/

-- Modifica la funzione per permettere DELETE da funzioni SECURITY DEFINER
CREATE OR REPLACE FUNCTION prevent_trial_plan_changes()
RETURNS TRIGGER AS $$
BEGIN
  -- Permetti agli admin di fare qualsiasi cosa
  IF EXISTS (
    SELECT 1 FROM admins 
    WHERE user_id = auth.uid()
  ) THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  -- Blocca DELETE durante trial solo se non viene da una funzione SECURITY DEFINER
  IF TG_OP = 'DELETE' THEN
    -- Permetti DELETE se il profilo dell'utente sta per essere eliminato
    -- (la funzione admin_delete_user_account usa SECURITY DEFINER)
    IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = OLD.customer_id) THEN
      RETURN OLD;
    END IF;
    
    IF OLD.status = 'trial' THEN
      RAISE EXCEPTION 'Non puoi cancellare un abbonamento durante il periodo di prova. Devi attendere la scadenza del trial.';
    END IF;
    RETURN OLD;
  END IF;

  -- Blocca INSERT se esiste già un trial attivo
  IF TG_OP = 'INSERT' THEN
    IF EXISTS (
      SELECT 1 FROM subscriptions
      WHERE customer_id = NEW.customer_id
        AND status = 'trial'
        AND trial_end_date > NOW()
    ) THEN
      RAISE EXCEPTION 'Hai già un periodo di prova attivo. Non puoi attivare un nuovo abbonamento fino alla scadenza del trial.';
    END IF;
    RETURN NEW;
  END IF;

  -- Blocca UPDATE del piano durante trial
  IF TG_OP = 'UPDATE' THEN
    IF OLD.status = 'trial' AND OLD.trial_end_date > NOW() THEN
      -- Permetti solo aggiornamenti a campi non-critici
      IF NEW.plan_id != OLD.plan_id THEN
        RAISE EXCEPTION 'Non puoi cambiare piano durante il periodo di prova. Se cambi piano perdi il diritto alla prova gratuita di 30 giorni.';
      END IF;
      
      -- Permetti solo modifica di payment_method_added, reminder_sent, status
      IF NEW.customer_id != OLD.customer_id OR
         NEW.start_date != OLD.start_date OR
         NEW.end_date != OLD.end_date OR
         NEW.trial_end_date != OLD.trial_end_date THEN
        RAISE EXCEPTION 'Non puoi modificare i dettagli dell''abbonamento durante il periodo di prova.';
      END IF;
    END IF;
    RETURN NEW;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


-- ============================================================
-- FILE: 20260326111904_cleanup_orphaned_subscriptions_v2.sql
-- ============================================================
/*
  # Pulizia Abbonamenti Orfani - v2
  
  1. Problema
    - Gli abbonamenti possono rimanere nel database dopo l'eliminazione di un utente
    - Questo causa confusione nel pannello admin
    
  2. Soluzione
    - Elimina tutti gli abbonamenti senza un customer valido
    - La funzione admin_delete_user_account già gestisce l'eliminazione
    
  3. Note
    - Pulizia una tantum degli abbonamenti orfani esistenti
    - Non serve trigger perché la funzione admin_delete_user_account già elimina gli abbonamenti
*/

-- Pulizia abbonamenti orfani esistenti (se ce ne sono)
DO $$
BEGIN
  DELETE FROM subscriptions
  WHERE customer_id NOT IN (SELECT id FROM profiles);
  
  RAISE NOTICE 'Abbonamenti orfani eliminati con successo';
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'Errore durante la pulizia: %', SQLERRM;
END $$;


-- ============================================================
-- FILE: 20260326142358_fix_subscription_type_constraint_allow_plan_names.sql
-- ============================================================
/*
  # Fix Subscription Type Constraint - Permetti Nomi Piano
  
  1. Problema
    - Il CHECK constraint su profiles.subscription_type permette solo 'monthly' o 'annual'
    - I trigger salvano il nome completo del piano (es. "Trial Base", "Business Base")
    - Causa errore: "new row violates check constraint profiles_subscription_type_check"
    
  2. Soluzione
    - Rimuove il constraint esistente
    - Aggiunge un nuovo constraint che permette NULL o qualsiasi stringa
    
  3. Note
    - Mantiene la compatibilità con i dati esistenti
    - Permette flessibilità per salvare qualsiasi nome di piano
*/

-- Rimuovi il constraint esistente
ALTER TABLE profiles 
DROP CONSTRAINT IF EXISTS profiles_subscription_type_check;

-- Aggiungi un nuovo constraint che permette NULL o qualsiasi valore text
ALTER TABLE profiles
ADD CONSTRAINT profiles_subscription_type_check 
CHECK (subscription_type IS NULL OR length(subscription_type) > 0);

-- Commento
COMMENT ON CONSTRAINT profiles_subscription_type_check ON profiles IS 'Permette NULL o qualsiasi nome di piano valido';


-- ============================================================
-- FILE: 20260326143138_fix_registration_subscription_conflicts.sql
-- ============================================================
/*
  # Fix Registration Subscription Conflicts
  
  1. Problema
    - Durante la registrazione vengono creati doppi abbonamenti:
      * Uno dal RegisterForm (frontend)
      * Uno dai trigger create_trial_for_customer/business (database)
    - Questo causa confusione e l'abbonamento non viene visualizzato
    
  2. Soluzione
    - Disattiva i trigger automatici di creazione trial
    - Lascia che sia solo il frontend a creare l'abbonamento
    - Il trigger sync_subscription_type_from_plan si occuperà di aggiornare il nome del piano
    
  3. Note
    - Il frontend gestirà la creazione completa dell'abbonamento
    - I trigger saranno solo di sincronizzazione, non di creazione
*/

-- Disabilita il trigger di creazione automatica trial per customer
DROP TRIGGER IF EXISTS trigger_create_trial_subscription_customer ON profiles;

-- Disabilita il trigger di creazione automatica trial per business
DROP TRIGGER IF EXISTS trigger_create_trial_subscription_business ON profiles;

-- Mantieni SOLO il trigger di sincronizzazione del subscription_type
-- (questo rimane attivo e funzionante)

-- Aggiungi commento per chiarezza
COMMENT ON FUNCTION create_trial_for_customer IS 'DISABILITATA - La creazione del trial è gestita dal frontend durante la registrazione';
COMMENT ON FUNCTION create_trial_for_business IS 'DISABILITATA - La creazione del trial è gestita dal frontend durante la registrazione';


-- ============================================================
-- FILE: 20260326143203_update_sync_trigger_include_expires_at.sql
-- ============================================================
/*
  # Update Sync Trigger - Include Expires At
  
  1. Problema
    - Il trigger sync_subscription_type_from_plan aggiorna solo subscription_type e status
    - Non aggiorna subscription_expires_at
    - Questo causa inconsistenza nei dati del profilo
    
  2. Soluzione
    - Aggiorna il trigger per includere anche subscription_expires_at
    - Prende la data di fine abbonamento dalla tabella subscriptions
    
  3. Note
    - Mantiene la sincronizzazione completa tra subscriptions e profiles
*/

CREATE OR REPLACE FUNCTION public.sync_subscription_type_from_plan()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  plan_name text;
BEGIN
  -- Ottieni il nome del piano
  SELECT name INTO plan_name
  FROM subscription_plans
  WHERE id = NEW.plan_id;
  
  -- Aggiorna il profilo con il nome del piano, lo status e la data di scadenza
  IF plan_name IS NOT NULL THEN
    UPDATE profiles
    SET 
      subscription_type = plan_name,
      subscription_status = NEW.status,
      subscription_expires_at = NEW.end_date
    WHERE id = NEW.customer_id;
  END IF;
  
  RETURN NEW;
END;
$$;

-- Commento esplicativo
COMMENT ON FUNCTION sync_subscription_type_from_plan IS 'Sincronizza subscription_type, status e expires_at dal piano selezionato in subscriptions';


-- ============================================================
-- FILE: 20260326143233_cleanup_duplicate_subscriptions_on_registration.sql
-- ============================================================
/*
  # Cleanup Duplicate Subscriptions
  
  1. Problema
    - Gli utenti potrebbero avere abbonamenti duplicati creati dai trigger e dal frontend
    - Questo causa confusione nella dashboard
    
  2. Soluzione
    - Identifica e rimuovi abbonamenti duplicati
    - Mantieni solo l'abbonamento più recente per ogni utente
    
  3. Sicurezza
    - Opera solo su abbonamenti trial
    - Non tocca abbonamenti attivi pagati
*/

-- Rimuovi abbonamenti duplicati, mantenendo solo il più recente per ogni utente
WITH duplicates AS (
  SELECT 
    id,
    customer_id,
    ROW_NUMBER() OVER (
      PARTITION BY customer_id 
      ORDER BY created_at DESC, id DESC
    ) as rn
  FROM subscriptions
  WHERE status IN ('trial', 'active')
)
DELETE FROM subscriptions
WHERE id IN (
  SELECT id 
  FROM duplicates 
  WHERE rn > 1
);

-- Aggiorna i profili che non hanno subscription_type impostato
-- ma hanno un abbonamento attivo
UPDATE profiles p
SET 
  subscription_type = sp.name,
  subscription_status = s.status,
  subscription_expires_at = s.end_date
FROM subscriptions s
JOIN subscription_plans sp ON s.plan_id = sp.id
WHERE p.id = s.customer_id
  AND s.status IN ('trial', 'active')
  AND (p.subscription_type IS NULL OR p.subscription_status IS NULL);


-- ============================================================
-- FILE: 20260326151557_fix_admin_delete_user_disable_trial_trigger.sql
-- ============================================================
/*
  # Fix Admin Delete User - Disable Trial Protection Trigger

  1. Problem
    - When admin tries to delete a user with an active trial subscription
    - The trigger "enforce_trial_plan_restrictions" blocks the deletion
    - Admin should be able to delete any user regardless of trial status

  2. Solution
    - Temporarily disable the trial protection trigger during deletion
    - Re-enable it after deletion completes
*/

CREATE OR REPLACE FUNCTION admin_delete_user_account(user_id_to_delete uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  caller_user_id uuid;
  is_caller_admin boolean;
  user_business_id uuid;
  user_fiscal_code text;
  family_fiscal_codes text[];
  family_member_ids uuid[];
BEGIN
  -- Ottieni l'ID dell'utente che sta chiamando la funzione
  caller_user_id := auth.uid();
  
  IF caller_user_id IS NULL THEN
    RAISE EXCEPTION 'Non autenticato';
  END IF;

  -- Verifica che il chiamante sia un admin
  SELECT EXISTS (
    SELECT 1 FROM admins WHERE user_id = caller_user_id
  ) INTO is_caller_admin;

  IF NOT COALESCE(is_caller_admin, false) THEN
    RAISE EXCEPTION 'Permesso negato: solo gli admin possono eliminare gli utenti';
  END IF;

  -- Verifica che l'utente da eliminare esista
  IF NOT EXISTS (SELECT 1 FROM profiles WHERE id = user_id_to_delete) THEN
    RAISE EXCEPTION 'Utente non trovato';
  END IF;

  -- Ottieni il codice fiscale dell'utente
  SELECT fiscal_code INTO user_fiscal_code
  FROM profiles
  WHERE id = user_id_to_delete;

  -- Ottieni i codici fiscali dei membri della famiglia
  SELECT array_agg(fiscal_code)
  INTO family_fiscal_codes
  FROM customer_family_members
  WHERE customer_id = user_id_to_delete
    AND fiscal_code IS NOT NULL
    AND fiscal_code != '';

  -- Ottieni gli ID dei membri della famiglia
  SELECT array_agg(id)
  INTO family_member_ids
  FROM customer_family_members
  WHERE customer_id = user_id_to_delete;

  -- ========================================
  -- DISABILITA TRIGGER DI PROTEZIONE TRIAL
  -- ========================================
  
  ALTER TABLE subscriptions DISABLE TRIGGER enforce_trial_plan_restrictions;

  -- ========================================
  -- GESTIONE RIFERIMENTI CHE DEVONO RESTARE
  -- ========================================
  
  -- Gestisci le recensioni approvate da questo utente (mantieni la review ma rimuovi il riferimento all'admin)
  UPDATE reviews SET approved_by = NULL WHERE approved_by = user_id_to_delete;

  -- Gestisci i report revisionati da questo utente (mantieni il report ma rimuovi il riferimento all'admin)
  UPDATE reports SET reviewed_by = NULL WHERE reviewed_by = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE CONTENUTI UTENTE CUSTOMER
  -- ========================================

  -- Elimina i preferiti dell'utente
  DELETE FROM favorite_businesses WHERE user_id = user_id_to_delete;
  DELETE FROM favorite_classified_ads WHERE user_id = user_id_to_delete;
  DELETE FROM favorite_job_postings WHERE user_id = user_id_to_delete;

  -- Elimina le redemptions degli sconti dell'utente
  DELETE FROM discount_redemptions WHERE customer_id = user_id_to_delete;

  -- Elimina TUTTE le recensioni dell'utente (proprie e dei membri della famiglia)
  DELETE FROM reviews WHERE customer_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM reviews WHERE family_member_id = ANY(family_member_ids);
  END IF;

  -- Elimina TUTTI gli annunci classificati (propri e dei membri della famiglia)
  DELETE FROM classified_ads WHERE user_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM classified_ads WHERE family_member_id = ANY(family_member_ids);
  END IF;

  -- Elimina le visualizzazioni degli annunci classificati
  DELETE FROM classified_ad_views WHERE user_id = user_id_to_delete;

  -- Elimina l'attività utente e i log
  DELETE FROM user_activity WHERE user_id = user_id_to_delete;
  DELETE FROM activity_log WHERE user_id = user_id_to_delete;
  
  -- Elimina i rewards
  DELETE FROM user_rewards WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE CONTENUTI BUSINESS
  -- ========================================

  -- Elimina le attività registrate (dalla tabella registered_businesses)
  DELETE FROM registered_business_locations WHERE business_id IN (
    SELECT id FROM registered_businesses WHERE owner_id = user_id_to_delete
  );
  DELETE FROM registered_businesses WHERE owner_id = user_id_to_delete;

  -- Elimina le attività aggiunte dall'utente (ma non ancora registrate)
  DELETE FROM unclaimed_business_locations WHERE added_by = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE JOB SEEKING
  -- ========================================

  -- Elimina le richieste di lavoro (proprie e dei membri della famiglia)
  DELETE FROM job_requests WHERE customer_id = user_id_to_delete;
  
  -- Elimina gli annunci job seeker dell'utente E dei membri della famiglia
  DELETE FROM job_seekers WHERE user_id = user_id_to_delete;
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM job_seekers WHERE family_member_id = ANY(family_member_ids);
  END IF;
  
  -- Elimina le visualizzazioni degli annunci di lavoro
  DELETE FROM job_views WHERE user_id = user_id_to_delete;
  
  -- Elimina le application inviate dall'utente
  DELETE FROM job_applications WHERE user_id = user_id_to_delete;

  -- Elimina annunci di lavoro creati come business
  DELETE FROM job_postings WHERE business_id IN (
    SELECT id FROM registered_businesses WHERE owner_id = user_id_to_delete
  );

  -- ========================================
  -- ELIMINAZIONE MESSAGGI (SISTEMA UNIFICATO)
  -- ========================================

  -- Elimina i messaggi inviati dall'utente
  DELETE FROM messages WHERE sender_id = user_id_to_delete;
  
  -- Elimina le conversazioni dove l'utente è partecipante (o i suoi familiari)
  DELETE FROM conversations WHERE 
    participant1_id = user_id_to_delete
    OR participant2_id = user_id_to_delete;
  
  -- Elimina conversazioni dei membri della famiglia
  IF family_member_ids IS NOT NULL AND array_length(family_member_ids, 1) > 0 THEN
    DELETE FROM conversations WHERE 
      participant1_family_member_id = ANY(family_member_ids)
      OR participant2_family_member_id = ANY(family_member_ids);
  END IF;

  -- ========================================
  -- ELIMINAZIONE SEGNALAZIONI E NOTIFICHE
  -- ========================================

  -- Elimina le segnalazioni fatte dall'utente
  DELETE FROM reports WHERE reporter_id = user_id_to_delete;

  -- Elimina le notifiche
  DELETE FROM notifications WHERE user_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE ABBONAMENTI E FAMIGLIA
  -- ========================================

  -- Elimina gli abbonamenti (ora possiamo farlo senza problemi)
  DELETE FROM subscriptions WHERE customer_id = user_id_to_delete;

  -- Riabilita il trigger di protezione trial
  ALTER TABLE subscriptions ENABLE TRIGGER enforce_trial_plan_restrictions;

  -- Elimina i membri della famiglia
  DELETE FROM customer_family_members WHERE customer_id = user_id_to_delete;

  -- ========================================
  -- ELIMINAZIONE TRIAL HISTORY
  -- ========================================

  -- Rimuovi il codice fiscale del titolare dalla trial history
  IF user_fiscal_code IS NOT NULL AND user_fiscal_code != '' THEN
    DELETE FROM trial_usage_history WHERE fiscal_code = user_fiscal_code;
  END IF;

  -- Rimuovi i codici fiscali dei membri della famiglia dalla trial history
  IF family_fiscal_codes IS NOT NULL AND array_length(family_fiscal_codes, 1) > 0 THEN
    DELETE FROM trial_usage_history WHERE fiscal_code = ANY(family_fiscal_codes);
  END IF;

  -- ========================================
  -- ELIMINAZIONE PROFILO E ACCOUNT AUTH
  -- ========================================

  -- Elimina il profilo
  DELETE FROM profiles WHERE id = user_id_to_delete;

  -- Elimina l'utente auth
  DELETE FROM auth.users WHERE id = user_id_to_delete;

  RAISE NOTICE 'Account eliminato completamente dall''admin %: %', caller_user_id, user_id_to_delete;

EXCEPTION
  WHEN OTHERS THEN
    -- In caso di errore, riabilita il trigger prima di propagare l'errore
    ALTER TABLE subscriptions ENABLE TRIGGER enforce_trial_plan_restrictions;
    RAISE;
END;
$$;

GRANT EXECUTE ON FUNCTION admin_delete_user_account(uuid) TO authenticated;

COMMENT ON FUNCTION admin_delete_user_account(uuid) IS 'Permette agli admin di eliminare completamente qualsiasi account utente. Eliminazione PERMANENTE e IRREVERSIBILE.';


-- ============================================================
-- FILE: 20260326153107_fix_auto_profile_creation_detect_user_type.sql
-- ============================================================
/*
  # Fix Auto Profile Creation - Detect User Type from Metadata

  1. Changes
    - Update handle_new_user to detect user_type from raw_user_meta_data
    - Support 'customer', 'business', and 'admin' types
    - Default to 'customer' if not specified

  2. Security
    - Maintains SECURITY DEFINER for proper permissions
*/

CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  extracted_full_name text;
  extracted_user_type text;
BEGIN
  -- Try to extract full_name from metadata (check both locations)
  extracted_full_name := COALESCE(
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'fullName',
    split_part(NEW.email, '@', 1)
  );
  
  -- Ensure we have a non-empty string
  IF extracted_full_name = '' OR extracted_full_name IS NULL THEN
    extracted_full_name := split_part(NEW.email, '@', 1);
  END IF;

  -- Extract user_type from metadata, default to 'customer'
  extracted_user_type := COALESCE(
    NEW.raw_user_meta_data->>'user_type',
    NEW.raw_user_meta_data->>'userType',
    'customer'
  );

  -- Validate user_type matches CHECK constraint
  IF extracted_user_type NOT IN ('customer', 'business', 'admin') THEN
    extracted_user_type := 'customer';
  END IF;

  -- Create profile only if it doesn't exist
  INSERT INTO public.profiles (id, email, full_name, user_type, created_at)
  VALUES (
    NEW.id,
    NEW.email,
    extracted_full_name,
    extracted_user_type,
    NOW()
  )
  ON CONFLICT (id) DO NOTHING;

  RETURN NEW;
END;
$$;


-- ============================================================
-- FILE: 20260326161113_add_services_description_to_registered_locations.sql
-- ============================================================
/*
  # Add services_description to registered_business_locations

  1. Changes
    - Add `services_description` text field to `registered_business_locations` table
    - This field stores a free-form text description of services offered at each location
    - Similar to the description field, but specifically for services

  2. Notes
    - Field is nullable to support existing locations
    - Stored as plain text for maximum flexibility
    - Can be edited by business owners and admins
*/

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_business_locations' AND column_name = 'services_description'
  ) THEN
    ALTER TABLE registered_business_locations 
    ADD COLUMN services_description text;
  END IF;
END $$;

COMMENT ON COLUMN registered_business_locations.services_description IS 'Free-form text description of services offered at this location';


-- ============================================================
-- FILE: 20260328221103_fix_registered_businesses_rls_policies.sql
-- ============================================================
/*
  # Fix Registered Businesses RLS Policies

  1. Changes
    - Drop and recreate policies for registered_businesses with separate SELECT, INSERT, UPDATE, DELETE
    - Ensure business owners can update their own businesses
    - Ensure admins can manage all businesses

  2. Security
    - Business owners can only modify their own businesses
    - Admins can modify any business
    - Anyone can view registered businesses
*/

-- Drop existing policies
DROP POLICY IF EXISTS "Business owners can manage their businesses" ON registered_businesses;
DROP POLICY IF EXISTS "Anyone can view registered businesses" ON registered_businesses;
DROP POLICY IF EXISTS "Admins can view all registered businesses" ON registered_businesses;
DROP POLICY IF EXISTS "Admins can update any registered business" ON registered_businesses;

-- Create separate policies for better clarity and control
CREATE POLICY "Anyone can view registered businesses"
  ON registered_businesses FOR SELECT
  USING (true);

CREATE POLICY "Business owners can insert their businesses"
  ON registered_businesses FOR INSERT TO authenticated
  WITH CHECK (owner_id = auth.uid());

CREATE POLICY "Business owners can update their businesses"
  ON registered_businesses FOR UPDATE TO authenticated
  USING (owner_id = auth.uid())
  WITH CHECK (owner_id = auth.uid());

CREATE POLICY "Business owners can delete their businesses"
  ON registered_businesses FOR DELETE TO authenticated
  USING (owner_id = auth.uid());

-- Admin policies
CREATE POLICY "Admins can insert any business"
  ON registered_businesses FOR INSERT TO authenticated
  WITH CHECK (is_admin());

CREATE POLICY "Admins can update any business"
  ON registered_businesses FOR UPDATE TO authenticated
  USING (is_admin())
  WITH CHECK (is_admin());

CREATE POLICY "Admins can delete any business"
  ON registered_businesses FOR DELETE TO authenticated
  USING (is_admin());


-- ============================================================
-- FILE: 20260328223444_add_billing_address_to_registered_businesses.sql
-- ============================================================
/*
  # Add billing_address column to registered_businesses

  1. Changes
    - Add `billing_address` column (text, nullable)
    - Add trigger to auto-update when billing address fields change
    
  2. Notes
    - billing_address = concatenation of billing street + number + postal code + city + province
    - Auto-updates via trigger on INSERT/UPDATE
*/

-- Add column if it doesn't exist
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'billing_address'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN billing_address text;
  END IF;
END $$;

-- Create function to update billing_address
CREATE OR REPLACE FUNCTION update_registered_business_billing_address()
RETURNS TRIGGER AS $$
BEGIN
  NEW.billing_address := CASE 
    WHEN NEW.billing_street IS NOT NULL THEN
      CONCAT_WS(', ',
        CONCAT_WS(' ', NEW.billing_street, NEW.billing_street_number),
        NEW.billing_postal_code,
        NEW.billing_city,
        UPPER(NEW.billing_province)
      )
    ELSE NULL
  END;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger
DROP TRIGGER IF EXISTS update_registered_business_billing_address_trigger ON registered_businesses;
CREATE TRIGGER update_registered_business_billing_address_trigger
  BEFORE INSERT OR UPDATE ON registered_businesses
  FOR EACH ROW
  EXECUTE FUNCTION update_registered_business_billing_address();

-- Update existing rows
UPDATE registered_businesses
SET billing_street = billing_street
WHERE billing_street IS NOT NULL;


-- ============================================================
-- FILE: 20260328223508_add_missing_fields_to_registered_businesses.sql
-- ============================================================
/*
  # Add missing fields to registered_businesses

  1. Changes
    - Add `phone` column (business phone number)
    - Add `office_street`, `office_street_number`, `office_postal_code`, `office_city`, `office_province` columns
    - Add `office_address` column (concatenated office address)
    - Add trigger to auto-update office_address
    
  2. Notes
    - These fields match the business registration form
    - office_address is auto-generated from office address components
*/

-- Add phone column
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'phone'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN phone text;
  END IF;
END $$;

-- Add office address columns
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'office_street'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN office_street text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'office_street_number'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN office_street_number text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'office_postal_code'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN office_postal_code text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'office_city'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN office_city text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'office_province'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN office_province text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'registered_businesses' AND column_name = 'office_address'
  ) THEN
    ALTER TABLE registered_businesses ADD COLUMN office_address text;
  END IF;
END $$;

-- Update trigger function to include office_address
CREATE OR REPLACE FUNCTION update_registered_business_billing_address()
RETURNS TRIGGER AS $$
BEGIN
  -- Update billing_address
  NEW.billing_address := CASE 
    WHEN NEW.billing_street IS NOT NULL THEN
      CONCAT_WS(', ',
        CONCAT_WS(' ', NEW.billing_street, NEW.billing_street_number),
        NEW.billing_postal_code,
        NEW.billing_city,
        UPPER(NEW.billing_province)
      )
    ELSE NULL
  END;

  -- Update office_address
  NEW.office_address := CASE 
    WHEN NEW.office_street IS NOT NULL THEN
      CONCAT_WS(', ',
        CONCAT_WS(' ', NEW.office_street, NEW.office_street_number),
        NEW.office_postal_code,
        NEW.office_city,
        UPPER(NEW.office_province)
      )
    ELSE NULL
  END;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Trigger already exists, no need to recreate


-- ============================================================
-- FILE: 20260403152627_update_search_add_source_field.sql
-- ============================================================
/*
  # Aggiorna funzione di ricerca per includere campo source

  1. Modifiche
    - Aggiunge il campo source alla funzione search_all_business_locations
    - Permette di identificare la provenienza dell'attività (imported, user_added, claimed, self_registered)
    - Questo campo serve per mostrare i badge corretti nel frontend

  2. Badge per tipo
    - imported = Badge viola "Importata"
    - user_added (verificata) = Badge blu "Aggiunta da Utente"
    - claimed = Badge verde "Attività Verificata"
    - self_registered = Badge verde "Attività Iscritta"
*/

DROP FUNCTION IF EXISTS search_all_business_locations(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_business_locations(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
RETURN QUERY

-- Sedi non rivendicate da database importato (unclaimed_business_locations con source='imported')
SELECT
  ubl.id,
  ubl.name,
  ubl.category_id,
  COALESCE(ubl.description, ''),
  ubl.street,
  ubl.city,
  ubl.province,
  ubl.region,
  ubl.postal_code,
  ubl.phone,
  ubl.email,
  ubl.website,
  ubl.business_hours,
  ubl.latitude,
  ubl.longitude,
  'unclaimed'::text as location_type,
  COALESCE(ubl.is_claimed, false) as is_claimed,
  (ubl.verification_badge = 'verified') as is_verified,
  NULL::uuid as business_id,
  ubl.claimed_by as owner_id,
  ubl.added_by,
  ubl.added_by_family_member_id,
  CASE
    WHEN ubl.added_by IS NOT NULL THEN 'user_added'
    ELSE 'imported'
  END::text as source,
  ubl.created_at
FROM unclaimed_business_locations ubl
WHERE (NOT COALESCE(ubl.is_claimed, false) OR ubl.claimed_by IS NULL)
  AND (search_query = '' OR ubl.name ILIKE '%' || search_query || '%')
  AND (search_city IS NULL OR LOWER(ubl.city) = LOWER(search_city))
  AND (search_province IS NULL OR ubl.province = search_province)
  AND (search_region IS NULL OR ubl.region ILIKE search_region)
  AND (search_category_id IS NULL OR ubl.category_id = search_category_id)
  -- Mostra solo le attività importate (senza added_by) o quelle aggiunte da utenti E verificate
  AND (ubl.added_by IS NULL OR ubl.verification_badge = 'verified')
  AND NOT verified_only

UNION ALL

-- Attività registrate da sole (registered_businesses)
SELECT
  rb.id,
  rb.name,
  rb.category_id,
  COALESCE(rb.description, ''),
  rb.address,
  rb.city,
  rb.province,
  rb.region,
  rb.postal_code,
  rb.phone,
  rb.email,
  rb.website,
  rb.business_hours::text,
  rb.latitude,
  rb.longitude,
  'self_registered'::text as location_type,
  COALESCE(rb.is_claimed, false) as is_claimed,
  true as is_verified,
  NULL::uuid as business_id,
  rb.owner_id,
  NULL::uuid as added_by,
  NULL::uuid as added_by_family_member_id,
  'self_registered'::text as source,
  rb.created_at
FROM registered_businesses rb
WHERE rb.owner_id IS NOT NULL
  AND (search_query = '' OR rb.name ILIKE '%' || search_query || '%')
  AND (search_city IS NULL OR LOWER(rb.city) = LOWER(search_city))
  AND (search_province IS NULL OR rb.province = search_province)
  AND (search_region IS NULL OR rb.region ILIKE search_region)
  AND (search_category_id IS NULL OR rb.category_id = search_category_id)

UNION ALL

-- Sedi rivendicate (business_locations) - attività che erano unclaimed e ora sono rivendicate
SELECT
  bl.id,
  b.name,
  b.category_id,
  COALESCE(bl.description, b.description, ''),
  bl.address,
  bl.city,
  bl.province,
  bl.region,
  bl.postal_code,
  bl.phone,
  bl.email,
  bl.website,
  bl.business_hours::text,
  bl.latitude,
  bl.longitude,
  'claimed'::text as location_type,
  true as is_claimed,
  true as is_verified,
  b.id as business_id,
  b.owner_id,
  NULL::uuid as added_by,
  NULL::uuid as added_by_family_member_id,
  'claimed'::text as source,
  bl.created_at
FROM business_locations bl
INNER JOIN businesses b ON b.id = bl.business_id
WHERE b.owner_id IS NOT NULL
  AND (search_query = '' OR b.name ILIKE '%' || search_query || '%')
  AND (search_city IS NULL OR LOWER(bl.city) = LOWER(search_city))
  AND (search_province IS NULL OR bl.province = search_province)
  AND (search_region IS NULL OR bl.region ILIKE search_region)
  AND (search_category_id IS NULL OR b.category_id = search_category_id)

ORDER BY
  -- Prima le attività verificate (iscritte o rivendicate)
  CASE
    WHEN source IN ('self_registered', 'claimed') THEN 1
    WHEN source = 'imported' THEN 2
    WHEN source = 'user_added' THEN 3
    ELSE 4
  END,
  name
LIMIT limit_count;
END;
$$;

-- ============================================================
-- FILE: 20260404212143_update_search_all_businesses_wrapper.sql
-- ============================================================
/*
  # Aggiorna la funzione wrapper search_all_businesses
  
  1. Modifiche
    - Aggiorna search_all_businesses per chiamare la nuova versione di search_all_business_locations
    - Include il nuovo campo 'source' nel tipo di ritorno
    - Include i campi added_by e added_by_family_member_id
  
  2. Dettagli
    - Questa funzione è un wrapper che chiama search_all_business_locations
    - Deve avere la stessa firma della funzione principale
    - Include tutte le tre fonti: unclaimed, registered, claimed
*/

DROP FUNCTION IF EXISTS search_all_businesses(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_businesses(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  RETURN QUERY
  SELECT * FROM search_all_business_locations(
    search_query,
    search_city,
    search_province,
    search_region,
    search_category_id,
    verified_only,
    limit_count
  );
END;
$$;


-- ============================================================
-- FILE: 20260404212716_fix_search_function_registered_businesses_columns.sql
-- ============================================================
/*
  # Fix funzione di ricerca per registered_businesses
  
  1. Problema
    - La tabella registered_businesses ha colonne diverse dalle altre
    - Usa office_* invece di address, city, province, region
    - Usa billing_city invece di city per la ricerca
  
  2. Soluzione
    - Aggiorna la funzione search_all_business_locations per usare le colonne corrette
    - Usa office_city e billing_city per la ricerca geografica
    - Combina office_street e office_street_number per l'address
*/

DROP FUNCTION IF EXISTS search_all_business_locations(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_business_locations(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
RETURN QUERY

-- Sedi non rivendicate da database importato (unclaimed_business_locations con source='imported')
SELECT
  ubl.id,
  ubl.name,
  ubl.category_id,
  COALESCE(ubl.description, ''),
  ubl.street,
  ubl.city,
  ubl.province,
  ubl.region,
  ubl.postal_code,
  ubl.phone,
  ubl.email,
  ubl.website,
  ubl.business_hours,
  ubl.latitude,
  ubl.longitude,
  'unclaimed'::text as location_type,
  COALESCE(ubl.is_claimed, false) as is_claimed,
  (ubl.verification_badge = 'verified') as is_verified,
  NULL::uuid as business_id,
  ubl.claimed_by as owner_id,
  ubl.added_by,
  ubl.added_by_family_member_id,
  CASE
    WHEN ubl.added_by IS NOT NULL THEN 'user_added'
    ELSE 'imported'
  END::text as source,
  ubl.created_at
FROM unclaimed_business_locations ubl
WHERE (NOT COALESCE(ubl.is_claimed, false) OR ubl.claimed_by IS NULL)
  AND (search_query = '' OR ubl.name ILIKE '%' || search_query || '%')
  AND (search_city IS NULL OR LOWER(ubl.city) = LOWER(search_city))
  AND (search_province IS NULL OR ubl.province = search_province)
  AND (search_region IS NULL OR ubl.region ILIKE search_region)
  AND (search_category_id IS NULL OR ubl.category_id = search_category_id)
  -- Mostra solo le attività importate (senza added_by) o quelle aggiunte da utenti E verificate
  AND (ubl.added_by IS NULL OR ubl.verification_badge = 'verified')
  AND NOT verified_only

UNION ALL

-- Attività registrate da sole (registered_businesses)
SELECT
  rb.id,
  rb.name,
  rb.category_id,
  COALESCE(rb.description, ''),
  COALESCE(rb.office_address, rb.office_street || ' ' || COALESCE(rb.office_street_number, ''), ''),
  COALESCE(rb.office_city, rb.billing_city, ''),
  COALESCE(rb.office_province, rb.billing_province, ''),
  ''::text as region, -- Non abbiamo region in registered_businesses
  COALESCE(rb.office_postal_code, rb.billing_postal_code, ''),
  rb.phone,
  rb.pec_email,
  rb.website,
  NULL::text as business_hours,
  NULL::numeric as latitude,
  NULL::numeric as longitude,
  'self_registered'::text as location_type,
  false as is_claimed,
  true as is_verified,
  NULL::uuid as business_id,
  rb.owner_id,
  NULL::uuid as added_by,
  NULL::uuid as added_by_family_member_id,
  'self_registered'::text as source,
  rb.created_at
FROM registered_businesses rb
WHERE rb.owner_id IS NOT NULL
  AND (search_query = '' OR rb.name ILIKE '%' || search_query || '%')
  AND (search_city IS NULL OR 
       LOWER(COALESCE(rb.office_city, rb.billing_city, '')) = LOWER(search_city))
  AND (search_province IS NULL OR 
       COALESCE(rb.office_province, rb.billing_province) = search_province)
  AND (search_region IS NULL) -- Non possiamo filtrare per region
  AND (search_category_id IS NULL OR rb.category_id = search_category_id)

UNION ALL

-- Sedi rivendicate (business_locations) - attività che erano unclaimed e ora sono rivendicate
SELECT
  bl.id,
  b.name,
  b.category_id,
  COALESCE(bl.description, b.description, ''),
  bl.address,
  bl.city,
  bl.province,
  bl.region,
  bl.postal_code,
  bl.phone,
  bl.email,
  bl.website,
  bl.business_hours::text,
  bl.latitude,
  bl.longitude,
  'claimed'::text as location_type,
  true as is_claimed,
  true as is_verified,
  b.id as business_id,
  b.owner_id,
  NULL::uuid as added_by,
  NULL::uuid as added_by_family_member_id,
  'claimed'::text as source,
  bl.created_at
FROM business_locations bl
INNER JOIN businesses b ON b.id = bl.business_id
WHERE b.owner_id IS NOT NULL
  AND (search_query = '' OR b.name ILIKE '%' || search_query || '%')
  AND (search_city IS NULL OR LOWER(bl.city) = LOWER(search_city))
  AND (search_province IS NULL OR bl.province = search_province)
  AND (search_region IS NULL OR bl.region ILIKE search_region)
  AND (search_category_id IS NULL OR b.category_id = search_category_id)

ORDER BY
  -- Prima le attività verificate (iscritte o rivendicate)
  CASE
    WHEN source IN ('self_registered', 'claimed') THEN 1
    WHEN source = 'imported' THEN 2
    WHEN source = 'user_added' THEN 3
    ELSE 4
  END,
  name
LIMIT limit_count;
END;
$$;


-- ============================================================
-- FILE: 20260404212746_fix_search_function_source_alias.sql
-- ============================================================
/*
  # Fix ambiguità colonna source nella funzione di ricerca
  
  1. Problema
    - Il nome della colonna "source" nel risultato confligge con il parametro nella CASE
    - ORDER BY non può distinguere tra la colonna e il parametro
  
  2. Soluzione
    - Usa una subquery con alias per evitare conflitti di nome
*/

DROP FUNCTION IF EXISTS search_all_business_locations(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_business_locations(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
RETURN QUERY

SELECT * FROM (
  -- Sedi non rivendicate da database importato (unclaimed_business_locations con source='imported')
  SELECT
    ubl.id,
    ubl.name,
    ubl.category_id,
    COALESCE(ubl.description, ''),
    ubl.street,
    ubl.city,
    ubl.province,
    ubl.region,
    ubl.postal_code,
    ubl.phone,
    ubl.email,
    ubl.website,
    ubl.business_hours,
    ubl.latitude,
    ubl.longitude,
    'unclaimed'::text as location_type,
    COALESCE(ubl.is_claimed, false) as is_claimed,
    (ubl.verification_badge = 'verified') as is_verified,
    NULL::uuid as business_id,
    ubl.claimed_by as owner_id,
    ubl.added_by,
    ubl.added_by_family_member_id,
    CASE
      WHEN ubl.added_by IS NOT NULL THEN 'user_added'
      ELSE 'imported'
    END::text as result_source,
    ubl.created_at
  FROM unclaimed_business_locations ubl
  WHERE (NOT COALESCE(ubl.is_claimed, false) OR ubl.claimed_by IS NULL)
    AND (search_query = '' OR ubl.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(ubl.city) = LOWER(search_city))
    AND (search_province IS NULL OR ubl.province = search_province)
    AND (search_region IS NULL OR ubl.region ILIKE search_region)
    AND (search_category_id IS NULL OR ubl.category_id = search_category_id)
    -- Mostra solo le attività importate (senza added_by) o quelle aggiunte da utenti E verificate
    AND (ubl.added_by IS NULL OR ubl.verification_badge = 'verified')
    AND NOT verified_only

  UNION ALL

  -- Attività registrate da sole (registered_businesses)
  SELECT
    rb.id,
    rb.name,
    rb.category_id,
    COALESCE(rb.description, ''),
    COALESCE(rb.office_address, rb.office_street || ' ' || COALESCE(rb.office_street_number, ''), ''),
    COALESCE(rb.office_city, rb.billing_city, ''),
    COALESCE(rb.office_province, rb.billing_province, ''),
    ''::text as region,
    COALESCE(rb.office_postal_code, rb.billing_postal_code, ''),
    rb.phone,
    rb.pec_email,
    rb.website,
    NULL::text as business_hours,
    NULL::numeric as latitude,
    NULL::numeric as longitude,
    'self_registered'::text as location_type,
    false as is_claimed,
    true as is_verified,
    NULL::uuid as business_id,
    rb.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'self_registered'::text as result_source,
    rb.created_at
  FROM registered_businesses rb
  WHERE rb.owner_id IS NOT NULL
    AND (search_query = '' OR rb.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR 
         LOWER(COALESCE(rb.office_city, rb.billing_city, '')) = LOWER(search_city))
    AND (search_province IS NULL OR 
         COALESCE(rb.office_province, rb.billing_province) = search_province)
    AND (search_region IS NULL)
    AND (search_category_id IS NULL OR rb.category_id = search_category_id)

  UNION ALL

  -- Sedi rivendicate (business_locations)
  SELECT
    bl.id,
    b.name,
    b.category_id,
    COALESCE(bl.description, b.description, ''),
    bl.address,
    bl.city,
    bl.province,
    bl.region,
    bl.postal_code,
    bl.phone,
    bl.email,
    bl.website,
    bl.business_hours::text,
    bl.latitude,
    bl.longitude,
    'claimed'::text as location_type,
    true as is_claimed,
    true as is_verified,
    b.id as business_id,
    b.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'claimed'::text as result_source,
    bl.created_at
  FROM business_locations bl
  INNER JOIN businesses b ON b.id = bl.business_id
  WHERE b.owner_id IS NOT NULL
    AND (search_query = '' OR b.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(bl.city) = LOWER(search_city))
    AND (search_province IS NULL OR bl.province = search_province)
    AND (search_region IS NULL OR bl.region ILIKE search_region)
    AND (search_category_id IS NULL OR b.category_id = search_category_id)
) all_results
ORDER BY
  -- Prima le attività verificate (iscritte o rivendicate)
  CASE
    WHEN all_results.result_source IN ('self_registered', 'claimed') THEN 1
    WHEN all_results.result_source = 'imported' THEN 2
    WHEN all_results.result_source = 'user_added' THEN 3
    ELSE 4
  END,
  all_results.name
LIMIT limit_count;
END;
$$;


-- ============================================================
-- FILE: 20260404214028_update_search_show_only_locations_not_businesses.sql
-- ============================================================
/*
  # Aggiorna ricerca per mostrare solo sedi, non attività
  
  1. Cambiamento
    - Rimuove registered_businesses dalla ricerca diretta
    - Mostra solo business_locations (sedi effettive)
    - Ogni sede è indipendente e recensibile
  
  2. Rationale
    - Un'attività può avere più sedi
    - Gli utenti cercano sedi fisiche, non l'entità aziendale
    - Ogni sede deve essere trovabile, recensibile e gestibile separatamente
*/

DROP FUNCTION IF EXISTS search_all_business_locations(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_business_locations(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
RETURN QUERY

SELECT * FROM (
  -- Sedi non rivendicate da database importato (unclaimed_business_locations)
  SELECT
    ubl.id,
    ubl.name,
    ubl.category_id,
    COALESCE(ubl.description, ''),
    ubl.street,
    ubl.city,
    ubl.province,
    ubl.region,
    ubl.postal_code,
    ubl.phone,
    ubl.email,
    ubl.website,
    ubl.business_hours,
    ubl.latitude,
    ubl.longitude,
    'unclaimed'::text as location_type,
    COALESCE(ubl.is_claimed, false) as is_claimed,
    (ubl.verification_badge = 'verified') as is_verified,
    NULL::uuid as business_id,
    ubl.claimed_by as owner_id,
    ubl.added_by,
    ubl.added_by_family_member_id,
    CASE
      WHEN ubl.added_by IS NOT NULL THEN 'user_added'
      ELSE 'imported'
    END::text as result_source,
    ubl.created_at
  FROM unclaimed_business_locations ubl
  WHERE (NOT COALESCE(ubl.is_claimed, false) OR ubl.claimed_by IS NULL)
    AND (search_query = '' OR ubl.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(ubl.city) = LOWER(search_city))
    AND (search_province IS NULL OR ubl.province = search_province)
    AND (search_region IS NULL OR ubl.region ILIKE search_region)
    AND (search_category_id IS NULL OR ubl.category_id = search_category_id)
    AND (ubl.added_by IS NULL OR ubl.verification_badge = 'verified')
    AND NOT verified_only

  UNION ALL

  -- Sedi di attività registrate (business_locations)
  -- Queste sono le sedi fisiche delle attività che si sono registrate
  SELECT
    bl.id,
    COALESCE(bl.internal_name, b.name) as name,
    b.category_id,
    COALESCE(bl.description, b.description, ''),
    bl.address,
    bl.city,
    bl.province,
    bl.region,
    bl.postal_code,
    bl.phone,
    bl.email,
    bl.website,
    bl.business_hours::text,
    bl.latitude,
    bl.longitude,
    'registered'::text as location_type,
    true as is_claimed,
    true as is_verified,
    b.id as business_id,
    b.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'registered'::text as result_source,
    bl.created_at
  FROM business_locations bl
  INNER JOIN businesses b ON b.id = bl.business_id
  WHERE b.owner_id IS NOT NULL
    AND (search_query = '' OR COALESCE(bl.internal_name, b.name) ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(bl.city) = LOWER(search_city))
    AND (search_province IS NULL OR bl.province = search_province)
    AND (search_region IS NULL OR bl.region ILIKE search_region)
    AND (search_category_id IS NULL OR b.category_id = search_category_id)
) all_results
ORDER BY
  -- Prima le attività registrate e verificate
  CASE
    WHEN all_results.result_source = 'registered' THEN 1
    WHEN all_results.result_source = 'imported' THEN 2
    WHEN all_results.result_source = 'user_added' THEN 3
    ELSE 4
  END,
  all_results.name
LIMIT limit_count;
END;
$$;


-- ============================================================
-- FILE: 20260404214132_update_search_include_registered_without_locations.sql
-- ============================================================
/*
  # Include attività registrate senza sedi nella ricerca
  
  1. Problema
    - Alcune attività in registered_businesses non hanno ancora sedi
    - Devono comunque apparire nella ricerca
  
  2. Soluzione temporanea
    - Include registered_businesses che non hanno sedi in business_locations
    - Quando creeranno le sedi, queste appariranno invece del record principale
*/

DROP FUNCTION IF EXISTS search_all_business_locations(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_business_locations(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
RETURN QUERY

SELECT * FROM (
  -- Sedi non rivendicate da database importato (unclaimed_business_locations)
  SELECT
    ubl.id,
    ubl.name,
    ubl.category_id,
    COALESCE(ubl.description, ''),
    ubl.street,
    ubl.city,
    ubl.province,
    ubl.region,
    ubl.postal_code,
    ubl.phone,
    ubl.email,
    ubl.website,
    ubl.business_hours,
    ubl.latitude,
    ubl.longitude,
    'unclaimed'::text as location_type,
    COALESCE(ubl.is_claimed, false) as is_claimed,
    (ubl.verification_badge = 'verified') as is_verified,
    NULL::uuid as business_id,
    ubl.claimed_by as owner_id,
    ubl.added_by,
    ubl.added_by_family_member_id,
    CASE
      WHEN ubl.added_by IS NOT NULL THEN 'user_added'
      ELSE 'imported'
    END::text as result_source,
    ubl.created_at
  FROM unclaimed_business_locations ubl
  WHERE (NOT COALESCE(ubl.is_claimed, false) OR ubl.claimed_by IS NULL)
    AND (search_query = '' OR ubl.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(ubl.city) = LOWER(search_city))
    AND (search_province IS NULL OR ubl.province = search_province)
    AND (search_region IS NULL OR ubl.region ILIKE search_region)
    AND (search_category_id IS NULL OR ubl.category_id = search_category_id)
    AND (ubl.added_by IS NULL OR ubl.verification_badge = 'verified')
    AND NOT verified_only

  UNION ALL

  -- Sedi di attività registrate (business_locations)
  SELECT
    bl.id,
    COALESCE(bl.internal_name, b.name) as name,
    b.category_id,
    COALESCE(bl.description, b.description, ''),
    bl.address,
    bl.city,
    bl.province,
    bl.region,
    bl.postal_code,
    bl.phone,
    bl.email,
    bl.website,
    bl.business_hours::text,
    bl.latitude,
    bl.longitude,
    'registered'::text as location_type,
    true as is_claimed,
    true as is_verified,
    b.id as business_id,
    b.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'registered'::text as result_source,
    bl.created_at
  FROM business_locations bl
  INNER JOIN businesses b ON b.id = bl.business_id
  WHERE b.owner_id IS NOT NULL
    AND (search_query = '' OR COALESCE(bl.internal_name, b.name) ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(bl.city) = LOWER(search_city))
    AND (search_province IS NULL OR bl.province = search_province)
    AND (search_region IS NULL OR bl.region ILIKE search_region)
    AND (search_category_id IS NULL OR b.category_id = search_category_id)
  
  UNION ALL
  
  -- Attività registrate senza sedi (fallback temporaneo)
  -- Queste appariranno SOLO se non hanno ancora creato sedi in business_locations
  SELECT
    rb.id,
    rb.name,
    rb.category_id,
    COALESCE(rb.description, ''),
    COALESCE(rb.office_address, 
             NULLIF(TRIM(COALESCE(rb.office_street, '') || ' ' || COALESCE(rb.office_street_number, '')), ''),
             'Da completare'),
    COALESCE(rb.office_city, rb.billing_city, 'Da completare'),
    COALESCE(rb.office_province, rb.billing_province, ''),
    ''::text as region,
    COALESCE(rb.office_postal_code, rb.billing_postal_code, ''),
    rb.phone,
    rb.pec_email,
    rb.website,
    NULL::text as business_hours,
    NULL::numeric as latitude,
    NULL::numeric as longitude,
    'registered_no_location'::text as location_type,
    true as is_claimed,
    true as is_verified,
    NULL::uuid as business_id,
    rb.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'registered'::text as result_source,
    rb.created_at
  FROM registered_businesses rb
  WHERE rb.owner_id IS NOT NULL
    -- Mostra solo se NON ha sedi in business_locations
    AND NOT EXISTS (
      SELECT 1 FROM business_locations bl
      INNER JOIN businesses b ON b.id = bl.business_id
      WHERE b.owner_id = rb.owner_id
      AND b.name = rb.name
    )
    AND (search_query = '' OR rb.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR 
         LOWER(COALESCE(rb.office_city, rb.billing_city, '')) = LOWER(search_city))
    AND (search_province IS NULL OR 
         COALESCE(rb.office_province, rb.billing_province) = search_province)
    AND (search_region IS NULL)
    AND (search_category_id IS NULL OR rb.category_id = search_category_id)
) all_results
ORDER BY
  CASE
    WHEN all_results.result_source = 'registered' THEN 1
    WHEN all_results.result_source = 'imported' THEN 2
    WHEN all_results.result_source = 'user_added' THEN 3
    ELSE 4
  END,
  all_results.name
LIMIT limit_count;
END;
$$;


-- ============================================================
-- FILE: 20260405145651_fix_search_function_include_registered_locations.sql
-- ============================================================
/*
  # Aggiorna ricerca per includere sedi registrate
  
  1. Problema
    - Le sedi in registered_business_locations non appaiono nella ricerca
    - Solo business_locations è incluso
  
  2. Soluzione
    - Aggiungi UNION per includere registered_business_locations
    - Ogni sede registrata deve apparire nei risultati di ricerca
*/

DROP FUNCTION IF EXISTS search_all_business_locations(text, text, text, text, uuid, boolean, integer);

CREATE OR REPLACE FUNCTION search_all_business_locations(
  search_query text DEFAULT '',
  search_city text DEFAULT NULL,
  search_province text DEFAULT NULL,
  search_region text DEFAULT NULL,
  search_category_id uuid DEFAULT NULL,
  verified_only boolean DEFAULT false,
  limit_count integer DEFAULT 50
)
RETURNS TABLE (
  id uuid,
  name text,
  category_id uuid,
  description text,
  address text,
  city text,
  province text,
  region text,
  postal_code text,
  phone text,
  email text,
  website text,
  business_hours text,
  latitude numeric,
  longitude numeric,
  location_type text,
  is_claimed boolean,
  is_verified boolean,
  business_id uuid,
  owner_id uuid,
  added_by uuid,
  added_by_family_member_id uuid,
  source text,
  created_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
RETURN QUERY

SELECT * FROM (
  -- Sedi non rivendicate da database importato (unclaimed_business_locations)
  SELECT
    ubl.id,
    ubl.name,
    ubl.category_id,
    COALESCE(ubl.description, ''),
    ubl.street,
    ubl.city,
    ubl.province,
    ubl.region,
    ubl.postal_code,
    ubl.phone,
    ubl.email,
    ubl.website,
    ubl.business_hours,
    ubl.latitude,
    ubl.longitude,
    'unclaimed'::text as location_type,
    COALESCE(ubl.is_claimed, false) as is_claimed,
    (ubl.verification_badge = 'verified') as is_verified,
    NULL::uuid as business_id,
    ubl.claimed_by as owner_id,
    ubl.added_by,
    ubl.added_by_family_member_id,
    CASE
      WHEN ubl.added_by IS NOT NULL THEN 'user_added'
      ELSE 'imported'
    END::text as result_source,
    ubl.created_at
  FROM unclaimed_business_locations ubl
  WHERE (NOT COALESCE(ubl.is_claimed, false) OR ubl.claimed_by IS NULL)
    AND (search_query = '' OR ubl.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(ubl.city) = LOWER(search_city))
    AND (search_province IS NULL OR ubl.province = search_province)
    AND (search_region IS NULL OR ubl.region ILIKE search_region)
    AND (search_category_id IS NULL OR ubl.category_id = search_category_id)
    AND (ubl.added_by IS NULL OR ubl.verification_badge = 'verified')
    AND NOT verified_only

  UNION ALL

  -- Sedi di attività registrate (business_locations)
  SELECT
    bl.id,
    COALESCE(bl.internal_name, b.name) as name,
    b.category_id,
    COALESCE(bl.description, b.description, ''),
    bl.address,
    bl.city,
    bl.province,
    bl.region,
    bl.postal_code,
    bl.phone,
    bl.email,
    bl.website,
    bl.business_hours::text,
    bl.latitude,
    bl.longitude,
    'registered'::text as location_type,
    true as is_claimed,
    true as is_verified,
    b.id as business_id,
    b.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'registered'::text as result_source,
    bl.created_at
  FROM business_locations bl
  INNER JOIN businesses b ON b.id = bl.business_id
  WHERE b.owner_id IS NOT NULL
    AND (search_query = '' OR COALESCE(bl.internal_name, b.name) ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(bl.city) = LOWER(search_city))
    AND (search_province IS NULL OR bl.province = search_province)
    AND (search_region IS NULL OR bl.region ILIKE search_region)
    AND (search_category_id IS NULL OR b.category_id = search_category_id)
  
  UNION ALL
  
  -- Sedi di attività registrate (registered_business_locations)
  -- Queste sono le sedi delle attività che si sono registrate tramite il form
  SELECT
    rbl.id,
    COALESCE(rbl.name, rbl.internal_name, rb.name) as name,
    rb.category_id,
    COALESCE(rbl.description, rb.description, ''),
    COALESCE(rbl.street, '') as address,
    rbl.city,
    rbl.province,
    ''::text as region,
    COALESCE(rbl.postal_code, '') as postal_code,
    rbl.phone,
    rbl.email,
    rb.website,
    rbl.business_hours::text,
    NULL::numeric as latitude,
    NULL::numeric as longitude,
    'registered'::text as location_type,
    true as is_claimed,
    true as is_verified,
    rb.id as business_id,
    rb.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'registered'::text as result_source,
    rbl.created_at
  FROM registered_business_locations rbl
  INNER JOIN registered_businesses rb ON rb.id = rbl.business_id
  WHERE rb.owner_id IS NOT NULL
    AND (search_query = '' OR 
         COALESCE(rbl.name, rbl.internal_name, rb.name) ILIKE '%' || search_query || '%' OR
         rb.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR LOWER(rbl.city) = LOWER(search_city))
    AND (search_province IS NULL OR rbl.province = search_province)
    AND (search_region IS NULL)
    AND (search_category_id IS NULL OR rb.category_id = search_category_id)
  
  UNION ALL
  
  -- Attività registrate senza sedi (fallback temporaneo)
  -- Queste appariranno SOLO se non hanno ancora creato sedi
  SELECT
    rb.id,
    rb.name,
    rb.category_id,
    COALESCE(rb.description, ''),
    COALESCE(rb.office_address, 
             NULLIF(TRIM(COALESCE(rb.office_street, '') || ' ' || COALESCE(rb.office_street_number, '')), ''),
             'Da completare'),
    COALESCE(rb.office_city, rb.billing_city, 'Da completare'),
    COALESCE(rb.office_province, rb.billing_province, ''),
    ''::text as region,
    COALESCE(rb.office_postal_code, rb.billing_postal_code, ''),
    rb.phone,
    rb.pec_email,
    rb.website,
    NULL::text as business_hours,
    NULL::numeric as latitude,
    NULL::numeric as longitude,
    'registered_no_location'::text as location_type,
    true as is_claimed,
    true as is_verified,
    NULL::uuid as business_id,
    rb.owner_id,
    NULL::uuid as added_by,
    NULL::uuid as added_by_family_member_id,
    'registered'::text as result_source,
    rb.created_at
  FROM registered_businesses rb
  WHERE rb.owner_id IS NOT NULL
    -- Mostra solo se NON ha sedi in registered_business_locations
    AND NOT EXISTS (
      SELECT 1 FROM registered_business_locations rbl
      WHERE rbl.business_id = rb.id
    )
    AND (search_query = '' OR rb.name ILIKE '%' || search_query || '%')
    AND (search_city IS NULL OR 
         LOWER(COALESCE(rb.office_city, rb.billing_city, '')) = LOWER(search_city))
    AND (search_province IS NULL OR 
         COALESCE(rb.office_province, rb.billing_province) = search_province)
    AND (search_region IS NULL)
    AND (search_category_id IS NULL OR rb.category_id = search_category_id)
) all_results
ORDER BY
  CASE
    WHEN all_results.result_source = 'registered' THEN 1
    WHEN all_results.result_source = 'imported' THEN 2
    WHEN all_results.result_source = 'user_added' THEN 3
    ELSE 4
  END,
  all_results.name
LIMIT limit_count;
END;
$$;


-- ============================================================
-- FILE: 20260405160148_create_auctions_system.sql
-- ============================================================
/*
  # Create Auctions System

  1. New Tables
    - `auctions`
      - Complete auction listing with all details
      - Tracks base price, duration, status
      - Includes deposit requirement (5€ for base ≤500€, 10€ for >500€)
      - Status: active, completed, cancelled, expired

    - `auction_bids`
      - All bids placed on auctions
      - Tracks bid amount and timestamp
      - Links to user/family member who placed bid

    - `auction_deposits`
      - Tracks deposit payments for auction participation
      - Amount based on base price (5€ or 10€)
      - Refunded after auction completion or expiration

    - `auction_completions`
      - Tracks completion confirmations from both parties
      - 48-hour window to confirm transaction
      - Both buyer and seller must confirm

  2. Security
    - Enable RLS on all tables
    - Users can create their own auctions
    - Users can view active auctions
    - Users can place bids after paying deposit
    - Admins have full access

  3. Storage
    - Create bucket for auction images
    - Allow authenticated users to upload
    - Public read access
*/

-- Create auctions table
CREATE TABLE IF NOT EXISTS auctions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid REFERENCES profiles(id) ON DELETE CASCADE,
  family_member_id uuid REFERENCES customer_family_members(id) ON DELETE SET NULL,
  title text NOT NULL,
  description text NOT NULL,
  base_price numeric NOT NULL CHECK (base_price > 0),
  current_price numeric NOT NULL DEFAULT 0,
  deposit_amount numeric NOT NULL,
  images text[] DEFAULT '{}',
  category text NOT NULL,
  condition text CHECK (condition IN ('new', 'like_new', 'good', 'fair', 'poor')),
  city text NOT NULL,
  province text NOT NULL,
  region text NOT NULL,
  status text NOT NULL DEFAULT 'active' CHECK (status IN ('active', 'completed', 'cancelled', 'expired')),
  ends_at timestamptz NOT NULL,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now(),
  winner_id uuid REFERENCES profiles(id) ON DELETE SET NULL,
  winner_family_member_id uuid REFERENCES customer_family_members(id) ON DELETE SET NULL,
  completed_at timestamptz,
  CONSTRAINT valid_end_date CHECK (ends_at > created_at)
);

-- Create auction_bids table
CREATE TABLE IF NOT EXISTS auction_bids (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  auction_id uuid NOT NULL REFERENCES auctions(id) ON DELETE CASCADE,
  user_id uuid NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  family_member_id uuid REFERENCES customer_family_members(id) ON DELETE SET NULL,
  bid_amount numeric NOT NULL CHECK (bid_amount > 0),
  created_at timestamptz DEFAULT now(),
  CONSTRAINT unique_user_bid_per_auction UNIQUE(auction_id, user_id, created_at)
);

-- Create auction_deposits table
CREATE TABLE IF NOT EXISTS auction_deposits (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  auction_id uuid NOT NULL REFERENCES auctions(id) ON DELETE CASCADE,
  user_id uuid NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  family_member_id uuid REFERENCES customer_family_members(id) ON DELETE SET NULL,
  amount numeric NOT NULL CHECK (amount IN (5, 10)),
  paid_at timestamptz DEFAULT now(),
  refunded boolean DEFAULT false,
  refunded_at timestamptz,
  CONSTRAINT unique_deposit_per_user_auction UNIQUE(auction_id, user_id)
);

-- Create auction_completions table
CREATE TABLE IF NOT EXISTS auction_completions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  auction_id uuid NOT NULL REFERENCES auctions(id) ON DELETE CASCADE,
  seller_confirmed boolean DEFAULT false,
  seller_confirmed_at timestamptz,
  buyer_confirmed boolean DEFAULT false,
  buyer_confirmed_at timestamptz,
  completion_deadline timestamptz NOT NULL,
  created_at timestamptz DEFAULT now(),
  CONSTRAINT unique_completion_per_auction UNIQUE(auction_id)
);

-- Create indexes for performance
CREATE INDEX IF NOT EXISTS idx_auctions_user_id ON auctions(user_id);
CREATE INDEX IF NOT EXISTS idx_auctions_status ON auctions(status);
CREATE INDEX IF NOT EXISTS idx_auctions_ends_at ON auctions(ends_at);
CREATE INDEX IF NOT EXISTS idx_auctions_category ON auctions(category);
CREATE INDEX IF NOT EXISTS idx_auctions_city ON auctions(city);
CREATE INDEX IF NOT EXISTS idx_auctions_province ON auctions(province);
CREATE INDEX IF NOT EXISTS idx_auctions_region ON auctions(region);
CREATE INDEX IF NOT EXISTS idx_auction_bids_auction_id ON auction_bids(auction_id);
CREATE INDEX IF NOT EXISTS idx_auction_bids_user_id ON auction_bids(user_id);
CREATE INDEX IF NOT EXISTS idx_auction_deposits_auction_id ON auction_deposits(auction_id);
CREATE INDEX IF NOT EXISTS idx_auction_deposits_user_id ON auction_deposits(user_id);
CREATE INDEX IF NOT EXISTS idx_auction_completions_auction_id ON auction_completions(auction_id);

-- Enable RLS
ALTER TABLE auctions ENABLE ROW LEVEL SECURITY;
ALTER TABLE auction_bids ENABLE ROW LEVEL SECURITY;
ALTER TABLE auction_deposits ENABLE ROW LEVEL SECURITY;
ALTER TABLE auction_completions ENABLE ROW LEVEL SECURITY;

-- RLS Policies for auctions

-- Public can view active auctions
CREATE POLICY "Anyone can view active auctions"
  ON auctions FOR SELECT
  USING (status = 'active' OR auth.uid() = user_id OR auth.uid() IN (
    SELECT user_id FROM admins
  ));

-- Users can view their own auctions regardless of status
CREATE POLICY "Users can view own auctions"
  ON auctions FOR SELECT
  TO authenticated
  USING (auth.uid() = user_id);

-- Authenticated users can create auctions
CREATE POLICY "Authenticated users can create auctions"
  ON auctions FOR INSERT
  TO authenticated
  WITH CHECK (auth.uid() = user_id);

-- Users can update their own auctions
CREATE POLICY "Users can update own auctions"
  ON auctions FOR UPDATE
  TO authenticated
  USING (auth.uid() = user_id)
  WITH CHECK (auth.uid() = user_id);

-- Users can delete their own auctions if no bids yet
CREATE POLICY "Users can delete own auctions without bids"
  ON auctions FOR DELETE
  TO authenticated
  USING (
    auth.uid() = user_id AND
    NOT EXISTS (SELECT 1 FROM auction_bids WHERE auction_id = id)
  );

-- Admins can do everything
CREATE POLICY "Admins have full access to auctions"
  ON auctions FOR ALL
  TO authenticated
  USING (auth.uid() IN (SELECT user_id FROM admins))
  WITH CHECK (auth.uid() IN (SELECT user_id FROM admins));

-- RLS Policies for auction_bids

-- Anyone can view bids on active auctions
CREATE POLICY "Anyone can view bids on active auctions"
  ON auction_bids FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM auctions
      WHERE auctions.id = auction_id
      AND (auctions.status = 'active' OR auctions.user_id = auth.uid())
    )
  );

-- Authenticated users can place bids if they paid deposit
CREATE POLICY "Users can place bids after paying deposit"
  ON auction_bids FOR INSERT
  TO authenticated
  WITH CHECK (
    auth.uid() = user_id AND
    EXISTS (
      SELECT 1 FROM auction_deposits
      WHERE auction_deposits.auction_id = auction_bids.auction_id
      AND auction_deposits.user_id = auth.uid()
      AND auction_deposits.refunded = false
    )
  );

-- Admins can do everything
CREATE POLICY "Admins have full access to bids"
  ON auction_bids FOR ALL
  TO authenticated
  USING (auth.uid() IN (SELECT user_id FROM admins))
  WITH CHECK (auth.uid() IN (SELECT user_id FROM admins));

-- RLS Policies for auction_deposits

-- Users can view their own deposits
CREATE POLICY "Users can view own deposits"
  ON auction_deposits FOR SELECT
  TO authenticated
  USING (auth.uid() = user_id);

-- Auction owners can view deposits for their auctions
CREATE POLICY "Auction owners can view deposits"
  ON auction_deposits FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM auctions
      WHERE auctions.id = auction_id
      AND auctions.user_id = auth.uid()
    )
  );

-- Users can create deposits
CREATE POLICY "Users can create deposits"
  ON auction_deposits FOR INSERT
  TO authenticated
  WITH CHECK (auth.uid() = user_id);

-- Admins can do everything
CREATE POLICY "Admins have full access to deposits"
  ON auction_deposits FOR ALL
  TO authenticated
  USING (auth.uid() IN (SELECT user_id FROM admins))
  WITH CHECK (auth.uid() IN (SELECT user_id FROM admins));

-- RLS Policies for auction_completions

-- Auction participants can view completions
CREATE POLICY "Auction participants can view completions"
  ON auction_completions FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM auctions
      WHERE auctions.id = auction_id
      AND (auctions.user_id = auth.uid() OR auctions.winner_id = auth.uid())
    )
  );

-- System creates completion records (admins)
CREATE POLICY "Admins can create completions"
  ON auction_completions FOR INSERT
  TO authenticated
  WITH CHECK (auth.uid() IN (SELECT user_id FROM admins));

-- Sellers and buyers can update their confirmation
CREATE POLICY "Participants can confirm completion"
  ON auction_completions FOR UPDATE
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM auctions
      WHERE auctions.id = auction_id
      AND (auctions.user_id = auth.uid() OR auctions.winner_id = auth.uid())
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM auctions
      WHERE auctions.id = auction_id
      AND (auctions.user_id = auth.uid() OR auctions.winner_id = auth.uid())
    )
  );

-- Admins can do everything
CREATE POLICY "Admins have full access to completions"
  ON auction_completions FOR ALL
  TO authenticated
  USING (auth.uid() IN (SELECT user_id FROM admins))
  WITH CHECK (auth.uid() IN (SELECT user_id FROM admins));

-- Create function to automatically set deposit amount based on base price
CREATE OR REPLACE FUNCTION set_auction_deposit_amount()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.base_price <= 500 THEN
    NEW.deposit_amount := 5;
  ELSE
    NEW.deposit_amount := 10;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger to set deposit amount
DROP TRIGGER IF EXISTS trigger_set_auction_deposit_amount ON auctions;
CREATE TRIGGER trigger_set_auction_deposit_amount
  BEFORE INSERT OR UPDATE OF base_price ON auctions
  FOR EACH ROW
  EXECUTE FUNCTION set_auction_deposit_amount();

-- Create function to update current price when new bid is placed
CREATE OR REPLACE FUNCTION update_auction_current_price()
RETURNS TRIGGER AS $$
BEGIN
  UPDATE auctions
  SET
    current_price = NEW.bid_amount,
    updated_at = now()
  WHERE id = NEW.auction_id;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger to update current price
DROP TRIGGER IF EXISTS trigger_update_auction_current_price ON auction_bids;
CREATE TRIGGER trigger_update_auction_current_price
  AFTER INSERT ON auction_bids
  FOR EACH ROW
  EXECUTE FUNCTION update_auction_current_price();

-- Create function to automatically expire auctions
CREATE OR REPLACE FUNCTION expire_auctions()
RETURNS void AS $$
BEGIN
  -- Mark auctions as expired if end time has passed and no winner
  UPDATE auctions
  SET status = 'expired', updated_at = now()
  WHERE status = 'active'
  AND ends_at < now()
  AND winner_id IS NULL;

  -- Mark auctions as completed if they have a winner and end time has passed
  UPDATE auctions
  SET
    status = 'completed',
    winner_id = (
      SELECT user_id
      FROM auction_bids
      WHERE auction_id = auctions.id
      ORDER BY bid_amount DESC, created_at ASC
      LIMIT 1
    ),
    winner_family_member_id = (
      SELECT family_member_id
      FROM auction_bids
      WHERE auction_id = auctions.id
      ORDER BY bid_amount DESC, created_at ASC
      LIMIT 1
    ),
    completed_at = now(),
    updated_at = now()
  WHERE status = 'active'
  AND ends_at < now()
  AND current_price > 0;

  -- Create completion records for newly completed auctions
  INSERT INTO auction_completions (auction_id, completion_deadline)
  SELECT id, now() + interval '48 hours'
  FROM auctions
  WHERE status = 'completed'
  AND completed_at > now() - interval '1 minute'
  AND NOT EXISTS (
    SELECT 1 FROM auction_completions WHERE auction_id = auctions.id
  );

  -- Refund deposits for expired auctions
  UPDATE auction_deposits
  SET refunded = true, refunded_at = now()
  WHERE auction_id IN (
    SELECT id FROM auctions WHERE status = 'expired'
  )
  AND refunded = false;
END;
$$ LANGUAGE plpgsql;

