-- ============================================================
-- FILE: 20260420202007_fix_unclaimed_business_points_only_on_approval.sql
-- ============================================================
/*
  # Fix: Award points for unclaimed businesses only on admin approval

  ## Problem
  The trigger `trigger_award_points_unclaimed_business` fires on INSERT and awards
  points immediately when a user adds a business, before the admin has a chance to
  review and approve it. The admin approval flow in the frontend also tries to award
  points, leading to double-awarding or premature points.

  ## Changes
  1. Drop the old INSERT trigger that awards points immediately
  2. Create a new UPDATE trigger that awards points only when `approval_status`
     changes to 'approved' and `points_awarded` is still false
  3. The new trigger function sets `points_awarded = true` to prevent double-awarding

  ## Security
  - No RLS changes
  - Points can only be awarded through admin approval flow
*/

-- 1. Drop the old INSERT trigger that awards points prematurely
DROP TRIGGER IF EXISTS trigger_award_points_unclaimed_business ON unclaimed_business_locations;

-- 2. Create new function that awards points only on approval
CREATE OR REPLACE FUNCTION award_points_for_unclaimed_business_on_approval()
RETURNS TRIGGER AS $$
DECLARE
  points_to_award INTEGER;
  is_complete BOOLEAN;
  v_family_member_id uuid;
BEGIN
  -- Only fire when approval_status changes to 'approved' and points not yet awarded
  IF NEW.approval_status = 'approved' 
     AND (OLD.approval_status IS DISTINCT FROM 'approved')
     AND (NEW.points_awarded IS NOT TRUE) THEN

    is_complete := (
      (NEW.email IS NOT NULL AND NEW.email != '') OR 
      (NEW.phone IS NOT NULL AND NEW.phone != '') OR 
      (NEW.website IS NOT NULL AND NEW.website != '')
    );

    IF is_complete THEN
      points_to_award := 25;
    ELSE
      points_to_award := 10;
    END IF;

    v_family_member_id := NEW.added_by_family_member_id;

    IF NEW.added_by IS NOT NULL THEN
      IF v_family_member_id IS NOT NULL THEN
        INSERT INTO user_activity (user_id, family_member_id, total_points, businesses_added_count, last_activity_at, created_at, updated_at)
        VALUES (NEW.added_by, v_family_member_id, points_to_award, 1, now(), now(), now())
        ON CONFLICT (user_id, family_member_id)
        DO UPDATE SET
          total_points = user_activity.total_points + points_to_award,
          businesses_added_count = user_activity.businesses_added_count + 1,
          last_activity_at = now(),
          updated_at = now();
      ELSE
        INSERT INTO user_activity (user_id, total_points, businesses_added_count, last_activity_at, created_at, updated_at)
        VALUES (NEW.added_by, points_to_award, 1, now(), now(), now())
        ON CONFLICT (user_id, family_member_id)
        DO UPDATE SET
          total_points = user_activity.total_points + points_to_award,
          businesses_added_count = user_activity.businesses_added_count + 1,
          last_activity_at = now(),
          updated_at = now()
        WHERE user_activity.family_member_id IS NULL;
      END IF;

      INSERT INTO activity_log (
        user_id,
        activity_type,
        title,
        description,
        points_earned,
        icon,
        color,
        metadata,
        created_at
      ) VALUES (
        NEW.added_by,
        'business_added',
        'Attività approvata',
        CASE 
          WHEN is_complete THEN 'La tua attività "' || NEW.name || '" è stata approvata (con dati completi)'
          ELSE 'La tua attività "' || NEW.name || '" è stata approvata'
        END,
        points_to_award,
        'building',
        'green',
        jsonb_build_object(
          'business_id', NEW.id,
          'business_name', NEW.name,
          'is_complete', is_complete,
          'family_member_id', v_family_member_id
        ),
        now()
      );

      -- Mark points as awarded to prevent double-awarding
      NEW.points_awarded := true;
    END IF;
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 3. Create the new trigger on UPDATE (BEFORE so we can modify NEW.points_awarded)
CREATE TRIGGER trigger_award_points_unclaimed_business_on_approval
  BEFORE UPDATE ON unclaimed_business_locations
  FOR EACH ROW
  EXECUTE FUNCTION award_points_for_unclaimed_business_on_approval();


-- ============================================================
-- FILE: 20260420204247_add_family_member_to_notifications.sql
-- ============================================================
/*
  # Add family member support to notifications

  ## Problem
  Notifications are currently tied only to user_id. In accounts with family members,
  all members see ALL notifications for the account. Each member should only see
  their own notifications.

  ## Changes
  1. Add `family_member_id` column to `notifications` table (nullable, for main account owner)
  2. Update `send_notification` function to accept optional family_member_id
  3. Update `get_unread_notification_count` to accept family_member_id parameter
  4. Update `mark_notification_read` - no changes needed (works by notification id)
  5. Update `mark_all_notifications_read` to accept family_member_id parameter
  6. Add index for efficient querying

  ## Important notes
  - family_member_id = NULL means the notification belongs to the main account owner
  - Existing notifications remain with family_member_id = NULL (main owner)
  - RLS stays the same (user_id based) since family members share the same auth user
*/

-- 1. Add family_member_id column
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'notifications' AND column_name = 'family_member_id'
  ) THEN
    ALTER TABLE notifications ADD COLUMN family_member_id uuid REFERENCES customer_family_members(id) ON DELETE CASCADE;
  END IF;
END $$;

-- 2. Add index for efficient queries
CREATE INDEX IF NOT EXISTS idx_notifications_user_family_member
  ON notifications (user_id, family_member_id);

-- 3. Update send_notification to support family_member_id
CREATE OR REPLACE FUNCTION send_notification(
  target_user_id uuid,
  notif_type text,
  notif_title text,
  notif_message text,
  notif_data jsonb DEFAULT '{}'::jsonb,
  target_family_member_id uuid DEFAULT NULL
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  IF NOT (is_admin() OR auth.uid() = target_user_id) THEN
    RAISE EXCEPTION 'Non autorizzato a inviare notifiche ad altri utenti';
  END IF;

  INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
  VALUES (target_user_id, target_family_member_id, notif_type, notif_title, notif_message, notif_data);
END;
$$;

-- 4. Update get_unread_notification_count to filter by family_member_id
CREATE OR REPLACE FUNCTION get_unread_notification_count(
  p_family_member_id uuid DEFAULT NULL
)
RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  count integer;
BEGIN
  IF p_family_member_id IS NOT NULL THEN
    SELECT COUNT(*)::integer INTO count
    FROM notifications
    WHERE user_id = auth.uid() AND family_member_id = p_family_member_id AND read = false;
  ELSE
    SELECT COUNT(*)::integer INTO count
    FROM notifications
    WHERE user_id = auth.uid() AND family_member_id IS NULL AND read = false;
  END IF;

  RETURN count;
END;
$$;

-- 5. Update mark_all_notifications_read to filter by family_member_id
CREATE OR REPLACE FUNCTION mark_all_notifications_read(
  p_family_member_id uuid DEFAULT NULL
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  IF p_family_member_id IS NOT NULL THEN
    UPDATE notifications
    SET read = true
    WHERE user_id = auth.uid() AND family_member_id = p_family_member_id AND read = false;
  ELSE
    UPDATE notifications
    SET read = true
    WHERE user_id = auth.uid() AND family_member_id IS NULL AND read = false;
  END IF;
END;
$$;

-- 6. Update the unclaimed business approval trigger to include family_member_id in notifications
-- The trigger award_points_for_unclaimed_business_on_approval already handles family_member_id
-- for points. Now we also need to make the frontend pass family_member_id when sending notifications.
-- This is handled in the frontend code changes.


-- ============================================================
-- FILE: 20260420204616_update_notification_triggers_add_family_member_id.sql
-- ============================================================
/*
  # Update notification trigger functions to use family_member_id column

  ## Problem
  The trigger functions `notify_ad_favorited` and `notify_job_seeker_favorited`
  store family_member_id only in the JSON `data` column but not in the new
  `family_member_id` column. This means notifications from these triggers
  won't be correctly filtered per family member.

  ## Changes
  1. Update `notify_ad_favorited` to set `family_member_id` column
  2. Update `notify_job_seeker_favorited` to set `family_member_id` column
  3. Update `notify_favorite_created` for completeness (no family member context)

  ## Notes
  - These triggers notify the owner of the ad/job/business when someone favorites it
  - The family_member_id refers to the family member who OWNS the ad/job, not the one who favorited it
*/

-- 1. Update notify_ad_favorited to include family_member_id column
CREATE OR REPLACE FUNCTION notify_ad_favorited()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_ad_title text;
  v_ad_owner_id uuid;
  v_ad_family_member_id uuid;
  v_favoriter_name text;
  v_family_member_name text;
BEGIN
  SELECT ca.title, ca.user_id, ca.family_member_id
  INTO v_ad_title, v_ad_owner_id, v_ad_family_member_id
  FROM classified_ads ca WHERE ca.id = NEW.ad_id;

  SELECT COALESCE(p.full_name, p.email) INTO v_favoriter_name
  FROM profiles p WHERE p.id = NEW.user_id;

  IF v_ad_family_member_id IS NOT NULL THEN
    SELECT COALESCE(nickname, first_name || ' ' || last_name) INTO v_family_member_name
    FROM customer_family_members WHERE id = v_ad_family_member_id;
  END IF;

  IF v_ad_owner_id IS NOT NULL AND v_ad_owner_id != NEW.user_id THEN
    INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
    VALUES (
      v_ad_owner_id,
      v_ad_family_member_id,
      'ad_favorited',
      'Annuncio aggiunto ai preferiti',
      format('L''annuncio "%s"%s è stato aggiunto ai preferiti da %s',
        v_ad_title,
        CASE WHEN v_family_member_name IS NOT NULL
             THEN ' di ' || v_family_member_name ELSE '' END,
        v_favoriter_name),
      jsonb_build_object(
        'ad_id', NEW.ad_id,
        'favorited_by', NEW.user_id,
        'family_member_id', v_ad_family_member_id,
        'url', '/classified-ads/' || NEW.ad_id)
    );
  END IF;
  RETURN NEW;
END;
$$;

-- 2. Update notify_job_seeker_favorited (if it exists as a trigger function)
CREATE OR REPLACE FUNCTION notify_job_seeker_favorited()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_job_title text;
  v_job_owner_id uuid;
  v_job_family_member_id uuid;
  v_favoriter_name text;
  v_family_member_name text;
BEGIN
  SELECT js.title, js.user_id, js.family_member_id
  INTO v_job_title, v_job_owner_id, v_job_family_member_id
  FROM job_seekers js WHERE js.id = NEW.job_seeker_id;

  SELECT COALESCE(p.full_name, p.email) INTO v_favoriter_name
  FROM profiles p WHERE p.id = NEW.user_id;

  IF v_job_family_member_id IS NOT NULL THEN
    SELECT COALESCE(nickname, first_name || ' ' || last_name) INTO v_family_member_name
    FROM customer_family_members WHERE id = v_job_family_member_id;
  END IF;

  IF v_job_owner_id IS NOT NULL AND v_job_owner_id != NEW.user_id THEN
    INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
    VALUES (
      v_job_owner_id,
      v_job_family_member_id,
      'job_favorited',
      'Annuncio lavoro nei preferiti',
      format('L''annuncio "%s"%s è stato aggiunto ai preferiti da %s',
        v_job_title,
        CASE WHEN v_family_member_name IS NOT NULL
             THEN ' di ' || v_family_member_name ELSE '' END,
        v_favoriter_name),
      jsonb_build_object(
        'job_seeker_id', NEW.job_seeker_id,
        'favorited_by', NEW.user_id,
        'family_member_id', v_job_family_member_id,
        'url', '/jobs')
    );
  END IF;
  RETURN NEW;
END;
$$;


-- ============================================================
-- FILE: 20260421090937_fix_award_points_ambiguous_function.sql
-- ============================================================
/*
  # Fix ambiguous award_points function

  ## Problem
  There are two versions of `award_points` with overlapping signatures:
  1. `award_points(uuid, integer, text, text DEFAULT NULL)` - old version without family member support
  2. `award_points(uuid, integer, text, text DEFAULT '', uuid DEFAULT NULL)` - new version with family member support

  When triggers call `award_points(uuid, integer, text, text)` with 4 arguments,
  Postgres cannot determine which function to use, causing ERROR 42725.

  This breaks classified_ads inserts (and any other trigger using award_points).

  ## Fix
  Drop the old function signature so only the new complete version remains.
*/

-- Drop the old version (without family_member_id parameter)
DROP FUNCTION IF EXISTS award_points(uuid, integer, text, text);


-- ============================================================
-- FILE: 20260421091043_fix_user_activity_on_conflict_family_member.sql
-- ============================================================
/*
  # Fix user_activity ON CONFLICT clauses for family member support

  ## Problem
  Multiple trigger/utility functions reference `ON CONFLICT (user_id)` on the
  `user_activity` table, but the unique constraint is now
  `(user_id, family_member_id)`. This causes ERROR 42P10 on any insert that
  fires these triggers.

  ## Affected functions
  1. `increment_ads_posted_count` - triggered on classified_ads insert
  2. `increment_user_added_business_count` - triggered on unclaimed_business insert
  3. `sync_user_activity` - bulk sync utility
  4. `populate_user_activity` - bulk populate utility

  ## Fix
  Update all four functions to use `ON CONFLICT (user_id, family_member_id)`.
  For trigger functions that have access to `family_member_id` via NEW, pass it through.
*/

-- 1. Fix increment_ads_posted_count (classified_ads has family_member_id)
CREATE OR REPLACE FUNCTION increment_ads_posted_count()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  INSERT INTO user_activity (user_id, family_member_id, ads_posted_count, last_activity_at, created_at, updated_at)
  VALUES (NEW.user_id, NEW.family_member_id, 1, now(), now(), now())
  ON CONFLICT (user_id, family_member_id)
  DO UPDATE SET
    ads_posted_count = user_activity.ads_posted_count + 1,
    last_activity_at = now(),
    updated_at = now();

  RETURN NEW;
END;
$$;

-- 2. Fix increment_user_added_business_count (unclaimed_business_locations has added_by_family_member_id)
CREATE OR REPLACE FUNCTION increment_user_added_business_count()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  INSERT INTO user_activity (user_id, family_member_id, businesses_added_count, last_activity_at, created_at, updated_at)
  VALUES (NEW.added_by, NEW.added_by_family_member_id, 1, now(), now(), now())
  ON CONFLICT (user_id, family_member_id)
  DO UPDATE SET
    businesses_added_count = user_activity.businesses_added_count + 1,
    last_activity_at = now(),
    updated_at = now();

  RETURN NEW;
END;
$$;

-- 3. Fix sync_user_activity
CREATE OR REPLACE FUNCTION sync_user_activity()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  INSERT INTO user_activity (user_id, family_member_id, total_points, reviews_count, last_activity_at, updated_at)
  SELECT
    p.id as user_id,
    NULL as family_member_id,
    COALESCE(SUM(CASE
      WHEN r.proof_image_url IS NOT NULL THEN 50
      ELSE 25
    END), 0) as total_points,
    COUNT(r.id) as reviews_count,
    NOW() as last_activity_at,
    NOW() as updated_at
  FROM profiles p
  LEFT JOIN reviews r ON r.customer_id = p.id
    AND r.family_member_id IS NULL
    AND r.review_status = 'approved'
  WHERE p.user_type = 'customer'
  GROUP BY p.id
  ON CONFLICT (user_id, family_member_id)
  DO UPDATE SET
    total_points = EXCLUDED.total_points,
    reviews_count = EXCLUDED.reviews_count,
    updated_at = NOW();
END;
$$;

-- 4. Fix populate_user_activity
CREATE OR REPLACE FUNCTION populate_user_activity()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  user_record RECORD;
  reviews_cnt INTEGER;
  ads_cnt INTEGER;
  jobs_cnt INTEGER;
  referrals_cnt INTEGER;
  points INTEGER;
BEGIN
  FOR user_record IN
    SELECT id, referral_count FROM profiles WHERE user_type IN ('customer', 'business')
  LOOP
    SELECT COUNT(*) INTO reviews_cnt
    FROM reviews
    WHERE customer_id = user_record.id AND review_status = 'approved';

    SELECT COUNT(*) INTO ads_cnt
    FROM classified_ads
    WHERE user_id = user_record.id AND status = 'active';

    SELECT COUNT(*) INTO jobs_cnt
    FROM job_seekers
    WHERE user_id = user_record.id AND status = 'active';

    referrals_cnt := COALESCE(user_record.referral_count, 0);

    SELECT
      COALESCE(SUM(
        CASE
          WHEN proof_image_url IS NOT NULL THEN 50
          ELSE 25
        END
      ), 0) INTO points
    FROM reviews
    WHERE customer_id = user_record.id AND review_status = 'approved';

    points := points + (ads_cnt * 10);
    points := points + (referrals_cnt * 100);

    INSERT INTO user_activity (
      user_id,
      family_member_id,
      total_points,
      reviews_count,
      ads_count,
      job_postings_count,
      referrals_count,
      last_activity_at,
      updated_at
    )
    VALUES (
      user_record.id,
      NULL,
      points,
      reviews_cnt,
      ads_cnt,
      jobs_cnt,
      referrals_cnt,
      now(),
      now()
    )
    ON CONFLICT (user_id, family_member_id) DO UPDATE SET
      total_points = EXCLUDED.total_points,
      reviews_count = EXCLUDED.reviews_count,
      ads_count = EXCLUDED.ads_count,
      job_postings_count = EXCLUDED.job_postings_count,
      referrals_count = EXCLUDED.referrals_count,
      last_activity_at = now(),
      updated_at = now();
  END LOOP;
END;
$$;


-- ============================================================
-- FILE: 20260421094304_fix_user_activity_duplicates_and_unique_constraint.sql
-- ============================================================
/*
  # Fix duplicate user_activity rows and add proper unique constraint

  ## Problem
  The unique constraint on `(user_id, family_member_id)` does not prevent
  duplicate rows when `family_member_id IS NULL`, because in SQL NULL != NULL.
  This causes `maybeSingle()` queries to fail and leaderboard data to not load.

  ## Fix
  1. Consolidate duplicate rows by summing up points and counts, keeping one row per user
  2. Add a unique index on `user_id` WHERE `family_member_id IS NULL` to prevent future duplicates
  3. Update the `award_points` function to use the correct ON CONFLICT target
*/

-- Step 1: Consolidate duplicates for rows where family_member_id IS NULL
DO $$
DECLARE
  r RECORD;
BEGIN
  FOR r IN
    SELECT user_id
    FROM user_activity
    WHERE family_member_id IS NULL
    GROUP BY user_id
    HAVING COUNT(*) > 1
  LOOP
    -- Sum up all the values into one row
    WITH agg AS (
      SELECT
        user_id,
        SUM(total_points) as total_points,
        SUM(reviews_count) as reviews_count,
        SUM(photos_count) as photos_count,
        SUM(businesses_added_count) as businesses_added_count,
        SUM(ads_posted_count) as ads_posted_count,
        SUM(COALESCE(ads_count, 0)) as ads_count,
        SUM(COALESCE(job_postings_count, 0)) as job_postings_count,
        SUM(COALESCE(referrals_count, 0)) as referrals_count,
        MAX(last_activity_at) as last_activity_at,
        MIN(created_at) as created_at
      FROM user_activity
      WHERE user_id = r.user_id AND family_member_id IS NULL
      GROUP BY user_id
    ),
    keep_one AS (
      SELECT ctid FROM user_activity
      WHERE user_id = r.user_id AND family_member_id IS NULL
      ORDER BY created_at ASC
      LIMIT 1
    )
    UPDATE user_activity
    SET
      total_points = agg.total_points,
      reviews_count = agg.reviews_count,
      photos_count = agg.photos_count,
      businesses_added_count = agg.businesses_added_count,
      ads_posted_count = agg.ads_posted_count,
      ads_count = agg.ads_count,
      job_postings_count = agg.job_postings_count,
      referrals_count = agg.referrals_count,
      last_activity_at = agg.last_activity_at,
      updated_at = now()
    FROM agg
    WHERE user_activity.ctid = (SELECT ctid FROM keep_one)
      AND user_activity.user_id = r.user_id;

    -- Delete all other duplicate rows
    DELETE FROM user_activity
    WHERE user_id = r.user_id
      AND family_member_id IS NULL
      AND ctid NOT IN (
        SELECT ctid FROM user_activity
        WHERE user_id = r.user_id AND family_member_id IS NULL
        ORDER BY created_at ASC
        LIMIT 1
      );
  END LOOP;
END $$;

-- Step 2: Create a unique partial index to prevent future duplicates
-- when family_member_id IS NULL
CREATE UNIQUE INDEX IF NOT EXISTS user_activity_user_id_null_family_unique
  ON user_activity (user_id)
  WHERE family_member_id IS NULL;


-- ============================================================
-- FILE: 20260421095511_add_classified_ads_approval_system_v2.sql
-- ============================================================
/*
  # Add approval system for classified ads

  Similar to the review approval system, classified ads now require admin
  approval before being visible and before points are awarded.

  ## Changes
  1. Add 'pending' to the status check constraint
  2. Add approval columns to `classified_ads`:
     - `approval_status` (text): 'pending', 'approved', 'rejected'
     - `approved_by` (uuid): admin who approved
     - `approved_at` (timestamptz): when approved
     - `points_awarded` (integer): points given after approval
  3. Set all existing active ads to 'approved' (grandfathered in)
  4. New ads default to 'pending' status
  5. Remove the automatic points trigger on INSERT
  6. Create `approve_classified_ad` and `reject_classified_ad` functions
  7. Update RLS: only approved+active ads visible publicly
  8. Fix Stefmanc's points to reflect actual approved activities
*/

-- Step 1: Update status check to include 'pending'
ALTER TABLE classified_ads DROP CONSTRAINT IF EXISTS classified_ads_status_check;
ALTER TABLE classified_ads ADD CONSTRAINT classified_ads_status_check
  CHECK (status IN ('pending', 'active', 'sold', 'expired', 'deleted'));

-- Step 2: Add approval columns
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'classified_ads' AND column_name = 'approval_status'
  ) THEN
    ALTER TABLE classified_ads ADD COLUMN approval_status text DEFAULT 'pending'
      CHECK (approval_status IN ('pending', 'approved', 'rejected'));
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'classified_ads' AND column_name = 'approved_by'
  ) THEN
    ALTER TABLE classified_ads ADD COLUMN approved_by uuid REFERENCES profiles(id);
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'classified_ads' AND column_name = 'approved_at'
  ) THEN
    ALTER TABLE classified_ads ADD COLUMN approved_at timestamptz;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'classified_ads' AND column_name = 'points_awarded'
  ) THEN
    ALTER TABLE classified_ads ADD COLUMN points_awarded integer DEFAULT 0;
  END IF;
END $$;

-- Step 3: Grandfather existing active ads as approved
UPDATE classified_ads
SET approval_status = 'approved', approved_at = created_at
WHERE status = 'active' AND approval_status = 'pending';

-- Step 4: Remove the automatic points trigger on INSERT
DROP TRIGGER IF EXISTS trigger_award_points_classified_ad ON classified_ads;

-- Step 5: New ads default to 'pending' status
ALTER TABLE classified_ads ALTER COLUMN status SET DEFAULT 'pending';

-- Step 6: Create approve_classified_ad function
CREATE OR REPLACE FUNCTION approve_classified_ad(
  ad_id_param uuid,
  staff_id_param uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  ad_record RECORD;
  points_to_award integer := 5;
BEGIN
  SELECT * INTO ad_record FROM classified_ads WHERE id = ad_id_param;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Annuncio non trovato';
  END IF;

  IF ad_record.approval_status != 'pending' THEN
    RAISE EXCEPTION 'L''annuncio e'' gia'' stato processato';
  END IF;

  UPDATE classified_ads
  SET approval_status = 'approved',
      status = 'active',
      approved_by = staff_id_param,
      approved_at = now(),
      points_awarded = points_to_award
  WHERE id = ad_id_param;

  PERFORM award_points(
    ad_record.user_id,
    points_to_award,
    'classified_ad',
    'Annuncio approvato',
    ad_record.family_member_id
  );

  INSERT INTO activity_log (user_id, action, details)
  VALUES (
    staff_id_param,
    'classified_ad_approved',
    jsonb_build_object(
      'ad_id', ad_id_param,
      'ad_title', ad_record.title,
      'points_awarded', points_to_award,
      'family_member_id', ad_record.family_member_id
    )
  );
END;
$$;

-- Step 7: Create reject_classified_ad function
CREATE OR REPLACE FUNCTION reject_classified_ad(
  ad_id_param uuid,
  staff_id_param uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  ad_record RECORD;
BEGIN
  SELECT * INTO ad_record FROM classified_ads WHERE id = ad_id_param;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Annuncio non trovato';
  END IF;

  IF ad_record.approval_status != 'pending' THEN
    RAISE EXCEPTION 'L''annuncio e'' gia'' stato processato';
  END IF;

  UPDATE classified_ads
  SET approval_status = 'rejected',
      approved_by = staff_id_param,
      approved_at = now(),
      points_awarded = 0
  WHERE id = ad_id_param;

  INSERT INTO activity_log (user_id, action, details)
  VALUES (
    staff_id_param,
    'classified_ad_rejected',
    jsonb_build_object(
      'ad_id', ad_id_param,
      'ad_title', ad_record.title,
      'family_member_id', ad_record.family_member_id
    )
  );
END;
$$;

-- Step 8: Update RLS - public can only see approved+active ads
DROP POLICY IF EXISTS "Anyone can view active ads" ON classified_ads;
DROP POLICY IF EXISTS "Users can view active classified ads" ON classified_ads;

CREATE POLICY "Anyone can view approved active ads"
  ON classified_ads FOR SELECT
  USING (status = 'active' AND approval_status = 'approved');

-- Step 9: Set Stefmanc's unapproved ad to pending
UPDATE classified_ads
SET status = 'pending', approval_status = 'pending'
WHERE id = '11e72704-13df-4551-ace9-f9f40a6e159d';

-- Step 10: Fix Stefmanc's main user points
-- Actual approved activities: 1 business approved = 25 pts, 0 ads approved = 0 pts
-- Total should be 25, not 30
UPDATE user_activity
SET total_points = 25,
    ads_posted_count = 0,
    updated_at = now()
WHERE user_id = '4ed5c590-7e6c-42f1-925b-2161dc7ad2be'
  AND family_member_id IS NULL;


-- ============================================================
-- FILE: 20260421095822_fix_ads_posted_count_on_approval_only.sql
-- ============================================================
/*
  # Fix ads posted count to only increment on approval

  ## Changes
  1. Remove the INSERT trigger that increments ads_posted_count immediately
  2. The approve_classified_ad function now handles counting via award_points
  3. Update approve function to also increment ads_posted_count

  ## Notes
  - ads_posted_count should reflect only approved ads
  - Points are already handled by the approve function
*/

-- Remove the old INSERT trigger
DROP TRIGGER IF EXISTS trigger_increment_ads_posted_count ON classified_ads;

-- Update approve function to also increment ads_posted_count
CREATE OR REPLACE FUNCTION approve_classified_ad(
  ad_id_param uuid,
  staff_id_param uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  ad_record RECORD;
  points_to_award integer := 5;
BEGIN
  SELECT * INTO ad_record FROM classified_ads WHERE id = ad_id_param;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Annuncio non trovato';
  END IF;

  IF ad_record.approval_status != 'pending' THEN
    RAISE EXCEPTION 'L''annuncio e'' gia'' stato processato';
  END IF;

  UPDATE classified_ads
  SET approval_status = 'approved',
      status = 'active',
      approved_by = staff_id_param,
      approved_at = now(),
      points_awarded = points_to_award
  WHERE id = ad_id_param;

  -- Award points
  PERFORM award_points(
    ad_record.user_id,
    points_to_award,
    'classified_ad',
    'Annuncio approvato',
    ad_record.family_member_id
  );

  -- Increment ads_posted_count
  INSERT INTO user_activity (user_id, family_member_id, ads_posted_count, last_activity_at)
  VALUES (ad_record.user_id, ad_record.family_member_id, 1, now())
  ON CONFLICT (user_id, family_member_id)
  DO UPDATE SET
    ads_posted_count = user_activity.ads_posted_count + 1,
    last_activity_at = now(),
    updated_at = now();

  -- Log the activity
  INSERT INTO activity_log (user_id, action, details)
  VALUES (
    staff_id_param,
    'classified_ad_approved',
    jsonb_build_object(
      'ad_id', ad_id_param,
      'ad_title', ad_record.title,
      'points_awarded', points_to_award,
      'family_member_id', ad_record.family_member_id
    )
  );
END;
$$;


-- ============================================================
-- FILE: 20260421100920_add_family_member_id_to_activity_log.sql
-- ============================================================
/*
  # Add family_member_id to activity_log for proper filtering

  ## Problem
  Activity log entries for family members are stored with the main user's
  user_id. The family_member_id is only in the metadata JSON, making it
  impossible to filter activities per family member.

  ## Changes
  1. Add `family_member_id` column to `activity_log`
  2. Backfill from metadata->>'family_member_id' for existing entries
  3. Update `log_user_activity` function to accept family_member_id
  4. Update business approval trigger to store family_member_id
  5. Update business add trigger to store family_member_id
  6. Update ad creation log trigger to store family_member_id
  7. Update review triggers to store family_member_id
*/

-- Step 1: Add family_member_id column
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'activity_log' AND column_name = 'family_member_id'
  ) THEN
    ALTER TABLE activity_log ADD COLUMN family_member_id uuid REFERENCES customer_family_members(id) ON DELETE CASCADE;
  END IF;
END $$;

-- Step 2: Backfill from metadata
UPDATE activity_log
SET family_member_id = (metadata->>'family_member_id')::uuid
WHERE family_member_id IS NULL
  AND metadata->>'family_member_id' IS NOT NULL
  AND metadata->>'family_member_id' != 'null'
  AND metadata->>'family_member_id' != '';

-- Step 3: Create index for fast filtering
CREATE INDEX IF NOT EXISTS idx_activity_log_family_member_id
  ON activity_log (family_member_id) WHERE family_member_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_activity_log_user_family
  ON activity_log (user_id, family_member_id);

-- Step 4: Update log_user_activity to accept family_member_id
CREATE OR REPLACE FUNCTION log_user_activity(
  p_user_id uuid,
  p_activity_type text,
  p_title text,
  p_description text,
  p_points_earned integer,
  p_metadata jsonb,
  p_icon text,
  p_color text,
  p_family_member_id uuid DEFAULT NULL
)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_activity_id uuid;
BEGIN
  INSERT INTO activity_log (
    user_id,
    family_member_id,
    activity_type,
    title,
    description,
    points_earned,
    metadata,
    icon,
    color
  )
  VALUES (
    p_user_id,
    p_family_member_id,
    p_activity_type,
    p_title,
    p_description,
    p_points_earned,
    p_metadata,
    p_icon,
    p_color
  )
  RETURNING id INTO v_activity_id;

  RETURN v_activity_id;
END;
$$;

-- Step 5: Update unclaimed business approval trigger to store family_member_id
CREATE OR REPLACE FUNCTION award_points_for_unclaimed_business_on_approval()
RETURNS TRIGGER AS $$
DECLARE
  points_to_award INTEGER;
  is_complete BOOLEAN;
  v_family_member_id uuid;
BEGIN
  IF NEW.approval_status = 'approved' 
    AND (OLD.approval_status IS DISTINCT FROM 'approved')
    AND (NEW.points_awarded IS NOT TRUE) THEN

    is_complete := (
      (NEW.email IS NOT NULL AND NEW.email != '') OR 
      (NEW.phone IS NOT NULL AND NEW.phone != '') OR 
      (NEW.website IS NOT NULL AND NEW.website != '')
    );

    IF is_complete THEN
      points_to_award := 25;
    ELSE
      points_to_award := 10;
    END IF;

    v_family_member_id := NEW.added_by_family_member_id;

    IF NEW.added_by IS NOT NULL THEN
      IF v_family_member_id IS NOT NULL THEN
        INSERT INTO user_activity (user_id, family_member_id, total_points, businesses_added_count, last_activity_at, created_at, updated_at)
        VALUES (NEW.added_by, v_family_member_id, points_to_award, 1, now(), now(), now())
        ON CONFLICT (user_id, family_member_id)
        DO UPDATE SET
          total_points = user_activity.total_points + points_to_award,
          businesses_added_count = user_activity.businesses_added_count + 1,
          last_activity_at = now(),
          updated_at = now();
      ELSE
        INSERT INTO user_activity (user_id, total_points, businesses_added_count, last_activity_at, created_at, updated_at)
        VALUES (NEW.added_by, points_to_award, 1, now(), now(), now())
        ON CONFLICT (user_id, family_member_id)
        DO UPDATE SET
          total_points = user_activity.total_points + points_to_award,
          businesses_added_count = user_activity.businesses_added_count + 1,
          last_activity_at = now(),
          updated_at = now()
        WHERE user_activity.family_member_id IS NULL;
      END IF;

      INSERT INTO activity_log (
        user_id,
        family_member_id,
        activity_type,
        title,
        description,
        points_earned,
        icon,
        color,
        metadata,
        created_at
      ) VALUES (
        NEW.added_by,
        v_family_member_id,
        'business_added',
        'Attività approvata',
        CASE 
          WHEN is_complete THEN 'La tua attività "' || NEW.name || '" è stata approvata (con dati completi)'
          ELSE 'La tua attività "' || NEW.name || '" è stata approvata'
        END,
        points_to_award,
        'building',
        'green',
        jsonb_build_object(
          'business_id', NEW.id,
          'business_name', NEW.name,
          'is_complete', is_complete,
          'family_member_id', v_family_member_id
        ),
        now()
      );

      NEW.points_awarded := true;
    END IF;
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Step 6: Update unclaimed business add trigger to store family_member_id
CREATE OR REPLACE FUNCTION award_points_for_unclaimed_business()
RETURNS TRIGGER AS $$
DECLARE
  points_to_award INTEGER;
  is_complete BOOLEAN;
  v_family_member_id uuid;
BEGIN
  is_complete := (
    (NEW.email IS NOT NULL AND NEW.email != '') OR 
    (NEW.phone IS NOT NULL AND NEW.phone != '') OR 
    (NEW.website IS NOT NULL AND NEW.website != '')
  );

  IF is_complete THEN
    points_to_award := 25;
  ELSE
    points_to_award := 10;
  END IF;

  v_family_member_id := NEW.added_by_family_member_id;

  IF v_family_member_id IS NOT NULL THEN
    INSERT INTO user_activity (user_id, family_member_id, total_points, businesses_added_count, last_activity_at, created_at, updated_at)
    VALUES (NEW.added_by, v_family_member_id, points_to_award, 1, now(), now(), now())
    ON CONFLICT (user_id, family_member_id)
    DO UPDATE SET
      total_points = user_activity.total_points + points_to_award,
      businesses_added_count = user_activity.businesses_added_count + 1,
      last_activity_at = now(),
      updated_at = now();
  ELSE
    INSERT INTO user_activity (user_id, total_points, businesses_added_count, last_activity_at, created_at, updated_at)
    VALUES (NEW.added_by, points_to_award, 1, now(), now(), now())
    ON CONFLICT (user_id, family_member_id)
    DO UPDATE SET
      total_points = user_activity.total_points + points_to_award,
      businesses_added_count = user_activity.businesses_added_count + 1,
      last_activity_at = now(),
      updated_at = now()
    WHERE user_activity.family_member_id IS NULL;
  END IF;

  INSERT INTO activity_log (
    user_id,
    family_member_id,
    activity_type,
    title,
    description,
    points_earned,
    icon,
    color,
    metadata,
    created_at
  ) VALUES (
    NEW.added_by,
    v_family_member_id,
    'business_added',
    'Attività aggiunta',
    CASE 
      WHEN is_complete THEN 'Hai aggiunto "' || NEW.name || '" con dati completi'
      ELSE 'Hai aggiunto "' || NEW.name || '"'
    END,
    points_to_award,
    'building',
    'green',
    jsonb_build_object(
      'business_id', NEW.id,
      'business_name', NEW.name,
      'is_complete', is_complete,
      'family_member_id', v_family_member_id
    ),
    now()
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Step 7: Update ad creation log trigger to store family_member_id
CREATE OR REPLACE FUNCTION log_ad_creation()
RETURNS TRIGGER AS $$
BEGIN
  PERFORM log_user_activity(
    NEW.user_id,
    'ad_created',
    'Annuncio inviato',
    'Hai inviato l''annuncio "' || NEW.title || '" per approvazione',
    0,
    jsonb_build_object('ad_id', NEW.id),
    'file-text',
    'text-blue-600',
    NEW.family_member_id
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Step 8: Update review submission trigger to store family_member_id
CREATE OR REPLACE FUNCTION log_review_submission()
RETURNS TRIGGER AS $$
DECLARE
  v_business_name text;
BEGIN
  SELECT name INTO v_business_name
  FROM business_locations
  WHERE business_id = NEW.business_id
  LIMIT 1;

  PERFORM log_user_activity(
    NEW.customer_id,
    'review_created',
    'Recensione inviata',
    'Hai recensito "' || COALESCE(v_business_name, 'un''attività') || '". In attesa di approvazione.',
    0,
    jsonb_build_object('review_id', NEW.id, 'business_id', NEW.business_id),
    'star',
    'text-yellow-600',
    NEW.family_member_id
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Step 9: Update review approval trigger to store family_member_id
CREATE OR REPLACE FUNCTION log_review_approval()
RETURNS TRIGGER AS $$
DECLARE
  v_business_name text;
  v_points integer;
BEGIN
  IF NEW.review_status = 'approved' AND OLD.review_status != 'approved' THEN
    SELECT name INTO v_business_name
    FROM business_locations
    WHERE business_id = NEW.business_id
    LIMIT 1;

    v_points := CASE 
      WHEN NEW.proof_image_url IS NOT NULL AND NEW.proof_image_url != '' THEN 50
      ELSE 25
    END;

    PERFORM log_user_activity(
      NEW.customer_id,
      'review_approved',
      'Recensione approvata!',
      'La tua recensione per "' || COALESCE(v_business_name, 'un''attività') || '" è stata approvata',
      v_points,
      jsonb_build_object(
        'review_id', NEW.id,
        'business_id', NEW.business_id,
        'has_proof', NEW.proof_image_url IS NOT NULL
      ),
      'star',
      'text-green-600',
      NEW.family_member_id
    );
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


-- ============================================================
-- FILE: 20260421140413_fix_award_points_and_approve_ad_null_family_member.sql
-- ============================================================
/*
  # Fix award_points and approve_classified_ad for NULL family_member_id

  ## Problem
  PostgreSQL treats NULL as unknown in unique constraints. The constraint
  `UNIQUE (user_id, family_member_id)` does not match ON CONFLICT when
  family_member_id is NULL. A separate partial unique index
  `user_activity_user_id_null_family_unique` exists for the NULL case,
  but ON CONFLICT (user_id, family_member_id) cannot target it.

  This causes HTTP 409 errors when approving classified ads (or awarding
  points) for users whose family_member_id is NULL.

  ## Fix
  1. Rewrite `award_points` to use explicit UPDATE-or-INSERT logic instead
     of ON CONFLICT, handling both NULL and non-NULL family_member_id correctly.
  2. Rewrite `approve_classified_ad` similarly for its direct user_activity insert.
*/

-- 1. Fix award_points function
CREATE OR REPLACE FUNCTION award_points(
  p_user_id uuid,
  p_points integer,
  p_activity_type text,
  p_description text DEFAULT '',
  p_family_member_id uuid DEFAULT NULL
)
RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_new_total integer;
  v_exists boolean;
BEGIN
  IF p_family_member_id IS NOT NULL THEN
    SELECT EXISTS(
      SELECT 1 FROM user_activity
      WHERE user_id = p_user_id AND family_member_id = p_family_member_id
    ) INTO v_exists;

    IF v_exists THEN
      UPDATE user_activity SET
        total_points = total_points + p_points,
        reviews_count = CASE WHEN p_activity_type = 'review' THEN reviews_count + 1 ELSE reviews_count END,
        last_activity_at = now(),
        updated_at = now()
      WHERE user_id = p_user_id AND family_member_id = p_family_member_id;
    ELSE
      INSERT INTO user_activity (user_id, family_member_id, total_points, reviews_count, last_activity_at, created_at, updated_at)
      VALUES (
        p_user_id,
        p_family_member_id,
        p_points,
        CASE WHEN p_activity_type = 'review' THEN 1 ELSE 0 END,
        now(), now(), now()
      );
    END IF;

    SELECT total_points INTO v_new_total
    FROM user_activity
    WHERE user_id = p_user_id AND family_member_id = p_family_member_id;
  ELSE
    SELECT EXISTS(
      SELECT 1 FROM user_activity
      WHERE user_id = p_user_id AND family_member_id IS NULL
    ) INTO v_exists;

    IF v_exists THEN
      UPDATE user_activity SET
        total_points = total_points + p_points,
        reviews_count = CASE WHEN p_activity_type = 'review' THEN reviews_count + 1 ELSE reviews_count END,
        last_activity_at = now(),
        updated_at = now()
      WHERE user_id = p_user_id AND family_member_id IS NULL;
    ELSE
      INSERT INTO user_activity (user_id, family_member_id, total_points, reviews_count, last_activity_at, created_at, updated_at)
      VALUES (
        p_user_id,
        NULL,
        p_points,
        CASE WHEN p_activity_type = 'review' THEN 1 ELSE 0 END,
        now(), now(), now()
      );
    END IF;

    SELECT total_points INTO v_new_total
    FROM user_activity
    WHERE user_id = p_user_id AND family_member_id IS NULL;
  END IF;

  RETURN v_new_total;
END;
$$;

-- 2. Fix approve_classified_ad function
CREATE OR REPLACE FUNCTION approve_classified_ad(
  ad_id_param uuid,
  staff_id_param uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  ad_record RECORD;
  points_to_award integer := 5;
  v_exists boolean;
BEGIN
  SELECT * INTO ad_record FROM classified_ads WHERE id = ad_id_param;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Annuncio non trovato';
  END IF;

  IF ad_record.approval_status != 'pending' THEN
    RAISE EXCEPTION 'L''annuncio e'' gia'' stato processato';
  END IF;

  UPDATE classified_ads
  SET approval_status = 'approved',
      status = 'active',
      approved_by = staff_id_param,
      approved_at = now(),
      points_awarded = points_to_award
  WHERE id = ad_id_param;

  -- Award points
  PERFORM award_points(
    ad_record.user_id,
    points_to_award,
    'classified_ad',
    'Annuncio approvato',
    ad_record.family_member_id
  );

  -- Increment ads_posted_count using explicit UPDATE-or-INSERT
  IF ad_record.family_member_id IS NOT NULL THEN
    SELECT EXISTS(
      SELECT 1 FROM user_activity
      WHERE user_id = ad_record.user_id AND family_member_id = ad_record.family_member_id
    ) INTO v_exists;

    IF v_exists THEN
      UPDATE user_activity SET
        ads_posted_count = ads_posted_count + 1,
        last_activity_at = now(),
        updated_at = now()
      WHERE user_id = ad_record.user_id AND family_member_id = ad_record.family_member_id;
    ELSE
      INSERT INTO user_activity (user_id, family_member_id, ads_posted_count, last_activity_at, created_at, updated_at)
      VALUES (ad_record.user_id, ad_record.family_member_id, 1, now(), now(), now());
    END IF;
  ELSE
    SELECT EXISTS(
      SELECT 1 FROM user_activity
      WHERE user_id = ad_record.user_id AND family_member_id IS NULL
    ) INTO v_exists;

    IF v_exists THEN
      UPDATE user_activity SET
        ads_posted_count = ads_posted_count + 1,
        last_activity_at = now(),
        updated_at = now()
      WHERE user_id = ad_record.user_id AND family_member_id IS NULL;
    ELSE
      INSERT INTO user_activity (user_id, family_member_id, ads_posted_count, last_activity_at, created_at, updated_at)
      VALUES (ad_record.user_id, NULL, 1, now(), now(), now());
    END IF;
  END IF;

  -- Log the activity
  INSERT INTO activity_log (user_id, family_member_id, action, details)
  VALUES (
    staff_id_param,
    NULL,
    'classified_ad_approved',
    jsonb_build_object(
      'ad_id', ad_id_param,
      'ad_title', ad_record.title,
      'points_awarded', points_to_award,
      'family_member_id', ad_record.family_member_id
    )
  );
END;
$$;

