    WHERE table_name = 'job_postings' AND column_name = 'approval_status'
  ) THEN
    ALTER TABLE job_postings ADD COLUMN approval_status text DEFAULT 'pending'
      CHECK (approval_status IN ('pending', 'approved', 'rejected'));
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'job_postings' AND column_name = 'approval_notes'
  ) THEN
    ALTER TABLE job_postings ADD COLUMN approval_notes text;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'job_postings' AND column_name = 'approved_at'
  ) THEN
    ALTER TABLE job_postings ADD COLUMN approved_at timestamptz;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'job_postings' AND column_name = 'approved_by'
  ) THEN
    ALTER TABLE job_postings ADD COLUMN approved_by uuid REFERENCES auth.users(id);
  END IF;
END $$;

-- Add auctions_count to user_activity if missing
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'user_activity' AND column_name = 'auctions_count'
  ) THEN
    ALTER TABLE user_activity ADD COLUMN auctions_count integer DEFAULT 0;
  END IF;
END $$;

-- Grandfather existing active job postings as approved
UPDATE job_postings SET approval_status = 'approved', approved_at = now()
WHERE status = 'active' AND approval_status = 'pending';

-- Create approve_job_posting function
CREATE OR REPLACE FUNCTION approve_job_posting(
  p_job_id uuid,
  p_admin_id uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_business_id uuid;
  v_owner_id uuid;
BEGIN
  -- Get job posting business
  SELECT jp.business_id INTO v_business_id
  FROM job_postings jp WHERE jp.id = p_job_id;

  IF v_business_id IS NULL THEN
    RAISE EXCEPTION 'Job posting not found';
  END IF;

  -- Get business owner
  SELECT owner_id INTO v_owner_id
  FROM businesses WHERE id = v_business_id;

  -- Update job posting
  UPDATE job_postings
  SET approval_status = 'approved',
      status = 'active',
      approved_at = now(),
      approved_by = p_admin_id
  WHERE id = p_job_id;

  -- Award 10 points to business owner if found
  IF v_owner_id IS NOT NULL THEN
    INSERT INTO user_activity (user_id, total_points, job_postings_count)
    VALUES (v_owner_id, 10, 1)
    ON CONFLICT (user_id, COALESCE(family_member_id, '00000000-0000-0000-0000-000000000000'))
    DO UPDATE SET
      total_points = user_activity.total_points + 10,
      job_postings_count = COALESCE(user_activity.job_postings_count, 0) + 1;

    -- Log activity
    INSERT INTO activity_log (user_id, action, details, points_awarded)
    VALUES (v_owner_id, 'job_posting_approved',
      jsonb_build_object('job_id', p_job_id), 10);

    -- Send notification
    INSERT INTO notifications (user_id, type, title, message)
    VALUES (v_owner_id, 'job_approved',
      'Annuncio di lavoro approvato',
      'Il tuo annuncio di lavoro è stato approvato ed è ora visibile. Hai guadagnato 10 punti!');
  END IF;
END;
$$;

-- Create reject_job_posting function
CREATE OR REPLACE FUNCTION reject_job_posting(
  p_job_id uuid,
  p_admin_id uuid,
  p_reason text DEFAULT ''
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_business_id uuid;
  v_owner_id uuid;
BEGIN
  SELECT jp.business_id INTO v_business_id
  FROM job_postings jp WHERE jp.id = p_job_id;

  IF v_business_id IS NULL THEN
    RAISE EXCEPTION 'Job posting not found';
  END IF;

  SELECT owner_id INTO v_owner_id
  FROM businesses WHERE id = v_business_id;

  UPDATE job_postings
  SET approval_status = 'rejected',
      approval_notes = p_reason,
      status = 'closed',
      approved_at = now(),
      approved_by = p_admin_id
  WHERE id = p_job_id;

  IF v_owner_id IS NOT NULL THEN
    INSERT INTO notifications (user_id, type, title, message)
    VALUES (v_owner_id, 'job_rejected',
      'Annuncio di lavoro non approvato',
      CASE WHEN p_reason != ''
        THEN 'Il tuo annuncio di lavoro non è stato approvato. Motivo: ' || p_reason
        ELSE 'Il tuo annuncio di lavoro non è stato approvato. Contatta l''assistenza per maggiori informazioni.'
      END);
  END IF;
END;
$$;

-- Add index for pending job postings
CREATE INDEX IF NOT EXISTS idx_job_postings_approval_status ON job_postings(approval_status);


-- ============================================================
-- FILE: 20260422074727_add_current_bidder_to_auctions.sql
-- ============================================================
/*
  # Add current bidder tracking to auctions

  1. Changes
    - Add `current_bidder_id` (uuid) column to auctions table
    - Add `current_bidder_nickname` (text) column to auctions table
    - Create trigger that updates these fields when a new bid is placed
    - Backfill existing auctions with their current top bidder

  2. Important Notes
    - These denormalized columns are auto-updated by a trigger on auction_bids
    - Provides instant access to top bidder info without extra joins
*/

-- Add columns
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'auctions' AND column_name = 'current_bidder_id'
  ) THEN
    ALTER TABLE auctions ADD COLUMN current_bidder_id uuid REFERENCES auth.users(id);
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'auctions' AND column_name = 'current_bidder_nickname'
  ) THEN
    ALTER TABLE auctions ADD COLUMN current_bidder_nickname text;
  END IF;
END $$;

-- Create trigger function to update current bidder on new bids
CREATE OR REPLACE FUNCTION update_auction_current_bidder()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_nickname text;
  v_current_max numeric;
BEGIN
  -- Check if this bid is actually the highest
  SELECT MAX(bid_amount) INTO v_current_max
  FROM auction_bids
  WHERE auction_id = NEW.auction_id;

  IF NEW.bid_amount >= v_current_max THEN
    -- Get the bidder's nickname or full name
    SELECT COALESCE(nickname, full_name, 'Utente')
    INTO v_nickname
    FROM profiles
    WHERE id = NEW.user_id;

    -- If bid was placed by a family member, use their nickname instead
    IF NEW.family_member_id IS NOT NULL THEN
      SELECT COALESCE(nickname, first_name, 'Utente')
      INTO v_nickname
      FROM customer_family_members
      WHERE id = NEW.family_member_id;
    END IF;

    -- Update the auction
    UPDATE auctions
    SET current_bidder_id = NEW.user_id,
        current_bidder_nickname = v_nickname,
        current_price = NEW.bid_amount
    WHERE id = NEW.auction_id;
  END IF;

  RETURN NEW;
END;
$$;

-- Drop existing trigger if any
DROP TRIGGER IF EXISTS trg_update_auction_current_bidder ON auction_bids;

-- Create trigger
CREATE TRIGGER trg_update_auction_current_bidder
  AFTER INSERT ON auction_bids
  FOR EACH ROW
  EXECUTE FUNCTION update_auction_current_bidder();

-- Backfill existing auctions with their current top bidder
UPDATE auctions a
SET current_bidder_id = sub.user_id,
    current_bidder_nickname = sub.nickname
FROM (
  SELECT DISTINCT ON (ab.auction_id)
    ab.auction_id,
    ab.user_id,
    COALESCE(
      CASE WHEN ab.family_member_id IS NOT NULL
        THEN (SELECT COALESCE(cfm.nickname, cfm.first_name) FROM customer_family_members cfm WHERE cfm.id = ab.family_member_id)
        ELSE NULL
      END,
      p.nickname,
      p.full_name,
      'Utente'
    ) AS nickname
  FROM auction_bids ab
  LEFT JOIN profiles p ON p.id = ab.user_id
  ORDER BY ab.auction_id, ab.bid_amount DESC
) sub
WHERE a.id = sub.auction_id AND a.current_price > 0;


