-- FILE: 20260503161539_fix_unique_conversation_nulls_not_distinct_v2.sql
-- ============================================================


-- ============================================================
-- FILE: 20260503163114_fix_get_or_create_conversation_no_update.sql
-- ============================================================
/*
  # Simplify get_or_create_conversation - remove problematic UPDATE logic

  ## Problem
  The ON CONFLICT DO UPDATE was triggering RLS WITH CHECK failures (409) even
  inside a SECURITY DEFINER function, because Supabase evaluates RLS on the
  UPDATE path of ON CONFLICT.

  ## Fix
  - Remove the UPDATE in ON CONFLICT (use DO NOTHING instead)
  - The SELECT at the top already finds and returns existing conversations
  - No backfill needed: new conversations will have the correct location_id going forward
*/

CREATE OR REPLACE FUNCTION public.get_or_create_conversation(
  p_user1_id uuid,
  p_user2_id uuid,
  p_conversation_type text,
  p_reference_id uuid,
  p_user1_family_member_id uuid DEFAULT NULL,
  p_user2_family_member_id uuid DEFAULT NULL,
  p_user1_location_id uuid DEFAULT NULL,
  p_user2_location_id uuid DEFAULT NULL
)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_conversation_id uuid;
  v_participant1_id uuid;
  v_participant2_id uuid;
  v_p1_family_member_id uuid;
  v_p2_family_member_id uuid;
  v_p1_location_id uuid;
  v_p2_location_id uuid;
BEGIN
  -- Order participants consistently (smaller UUID first)
  IF p_user1_id < p_user2_id THEN
    v_participant1_id := p_user1_id;
    v_participant2_id := p_user2_id;
    v_p1_family_member_id := p_user1_family_member_id;
    v_p2_family_member_id := p_user2_family_member_id;
    v_p1_location_id := p_user1_location_id;
    v_p2_location_id := p_user2_location_id;
  ELSE
    v_participant1_id := p_user2_id;
    v_participant2_id := p_user1_id;
    v_p1_family_member_id := p_user2_family_member_id;
    v_p2_family_member_id := p_user1_family_member_id;
    v_p1_location_id := p_user2_location_id;
    v_p2_location_id := p_user1_location_id;
  END IF;

  -- Look for existing conversation (exact match including location)
  SELECT id INTO v_conversation_id
  FROM conversations
  WHERE participant1_id = v_participant1_id
    AND participant2_id = v_participant2_id
    AND conversation_type = p_conversation_type
    AND reference_id = p_reference_id
    AND participant1_family_member_id IS NOT DISTINCT FROM v_p1_family_member_id
    AND participant2_family_member_id IS NOT DISTINCT FROM v_p2_family_member_id
    AND participant1_location_id IS NOT DISTINCT FROM v_p1_location_id
    AND participant2_location_id IS NOT DISTINCT FROM v_p2_location_id
  LIMIT 1;

  IF v_conversation_id IS NOT NULL THEN
    RETURN v_conversation_id;
  END IF;

  -- Insert new conversation
  INSERT INTO conversations (
    participant1_id,
    participant2_id,
    conversation_type,
    reference_id,
    participant1_family_member_id,
    participant2_family_member_id,
    participant1_location_id,
    participant2_location_id,
    ad_id
  )
  VALUES (
    v_participant1_id,
    v_participant2_id,
    p_conversation_type,
    p_reference_id,
    v_p1_family_member_id,
    v_p2_family_member_id,
    v_p1_location_id,
    v_p2_location_id,
    CASE WHEN p_conversation_type = 'classified_ad' THEN p_reference_id ELSE NULL END
  )
  ON CONFLICT ON CONSTRAINT unique_conversation_with_context
  DO NOTHING;

  -- Fetch the id whether inserted or already existing
  SELECT id INTO v_conversation_id
  FROM conversations
  WHERE participant1_id = v_participant1_id
    AND participant2_id = v_participant2_id
    AND conversation_type = p_conversation_type
    AND reference_id = p_reference_id
    AND participant1_family_member_id IS NOT DISTINCT FROM v_p1_family_member_id
    AND participant2_family_member_id IS NOT DISTINCT FROM v_p2_family_member_id
    AND participant1_location_id IS NOT DISTINCT FROM v_p1_location_id
    AND participant2_location_id IS NOT DISTINCT FROM v_p2_location_id
  LIMIT 1;

  RETURN v_conversation_id;
END;
$$;


-- ============================================================
-- FILE: 20260503164352_fix_get_or_create_conversation_ignore_location_in_lookup.sql
-- ============================================================
/*
  # Fix get_or_create_conversation - ignore location_id in existence check

  ## Problem
  When participant ordering swaps user1/user2 (based on UUID comparison), the
  location_id ends up on a different participant slot than the existing conversation.
  This makes the SELECT miss the existing row and attempt an INSERT that violates
  the unique constraint → 409 error.

  ## Fix
  - First SELECT: find existing conversation by participants + type + reference ONLY
    (ignore family_member_id and location_id — these are context, not identity)
  - If found: return it immediately (no update needed)
  - If not found: INSERT with full context, DO NOTHING on conflict, then SELECT again
*/

CREATE OR REPLACE FUNCTION public.get_or_create_conversation(
  p_user1_id uuid,
  p_user2_id uuid,
  p_conversation_type text,
  p_reference_id uuid,
  p_user1_family_member_id uuid DEFAULT NULL,
  p_user2_family_member_id uuid DEFAULT NULL,
  p_user1_location_id uuid DEFAULT NULL,
  p_user2_location_id uuid DEFAULT NULL
)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_conversation_id uuid;
  v_participant1_id uuid;
  v_participant2_id uuid;
  v_p1_family_member_id uuid;
  v_p2_family_member_id uuid;
  v_p1_location_id uuid;
  v_p2_location_id uuid;
BEGIN
  -- Order participants consistently (smaller UUID first)
  IF p_user1_id < p_user2_id THEN
    v_participant1_id := p_user1_id;
    v_participant2_id := p_user2_id;
    v_p1_family_member_id := p_user1_family_member_id;
    v_p2_family_member_id := p_user2_family_member_id;
    v_p1_location_id := p_user1_location_id;
    v_p2_location_id := p_user2_location_id;
  ELSE
    v_participant1_id := p_user2_id;
    v_participant2_id := p_user1_id;
    v_p1_family_member_id := p_user2_family_member_id;
    v_p2_family_member_id := p_user1_family_member_id;
    v_p1_location_id := p_user2_location_id;
    v_p2_location_id := p_user1_location_id;
  END IF;

  -- Look for existing conversation by core identity only (participants + type + reference)
  -- Ignore location/family context so we always find the existing row regardless of
  -- which slot the location ended up in during a previous call
  SELECT id INTO v_conversation_id
  FROM conversations
  WHERE participant1_id = v_participant1_id
    AND participant2_id = v_participant2_id
    AND conversation_type = p_conversation_type
    AND reference_id = p_reference_id
  LIMIT 1;

  IF v_conversation_id IS NOT NULL THEN
    RETURN v_conversation_id;
  END IF;

  -- Insert new conversation with full context
  INSERT INTO conversations (
    participant1_id,
    participant2_id,
    conversation_type,
    reference_id,
    participant1_family_member_id,
    participant2_family_member_id,
    participant1_location_id,
    participant2_location_id,
    ad_id
  )
  VALUES (
    v_participant1_id,
    v_participant2_id,
    p_conversation_type,
    p_reference_id,
    v_p1_family_member_id,
    v_p2_family_member_id,
    v_p1_location_id,
    v_p2_location_id,
    CASE WHEN p_conversation_type = 'classified_ad' THEN p_reference_id ELSE NULL END
  )
  ON CONFLICT ON CONSTRAINT unique_conversation_with_context
  DO NOTHING;

  -- Fetch the id whether inserted or conflicted
  SELECT id INTO v_conversation_id
  FROM conversations
  WHERE participant1_id = v_participant1_id
    AND participant2_id = v_participant2_id
    AND conversation_type = p_conversation_type
    AND reference_id = p_reference_id
  LIMIT 1;

  RETURN v_conversation_id;
END;
$$;


-- ============================================================
-- FILE: 20260503173936_fix_conversation_location_id_lookup.sql
-- ============================================================
/*
  # Fix conversation location_id - support both business_locations and registered_business_locations

  ## Problem
  conversations.participant1_location_id and participant2_location_id have FK constraints
  pointing only to business_locations. But the frontend also passes registered_business_location_id
  values (from registered_business_locations table), causing FK violations → HTTP 409.

  ## Fix
  - Drop the FK constraints on participant1_location_id and participant2_location_id
  - Add equivalent FK constraints to registered_business_locations for the same columns
    is not feasible (one column can't FK two tables)
  - Solution: drop FK constraints entirely, store UUID references loosely
    (the existing unique constraint and indexes are sufficient)
  - Update get_or_create_conversation to also check registered_business_locations
    and pass NULL if the location_id doesn't exist in either table
*/

-- Drop FK constraints on location columns (they're too restrictive)
ALTER TABLE conversations 
  DROP CONSTRAINT IF EXISTS conversations_participant1_location_id_fkey,
  DROP CONSTRAINT IF EXISTS conversations_participant2_location_id_fkey;

-- Replace the function to validate location_id exists in either locations table
CREATE OR REPLACE FUNCTION public.get_or_create_conversation(
  p_user1_id uuid,
  p_user2_id uuid,
  p_conversation_type text,
  p_reference_id uuid,
  p_user1_family_member_id uuid DEFAULT NULL,
  p_user2_family_member_id uuid DEFAULT NULL,
  p_user1_location_id uuid DEFAULT NULL,
  p_user2_location_id uuid DEFAULT NULL
)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_conversation_id uuid;
  v_participant1_id uuid;
  v_participant2_id uuid;
  v_p1_family_member_id uuid;
  v_p2_family_member_id uuid;
  v_p1_location_id uuid;
  v_p2_location_id uuid;
  v_loc_exists boolean;
BEGIN
  -- Order participants consistently (smaller UUID first)
  IF p_user1_id < p_user2_id THEN
    v_participant1_id := p_user1_id;
    v_participant2_id := p_user2_id;
    v_p1_family_member_id := p_user1_family_member_id;
    v_p2_family_member_id := p_user2_family_member_id;
    v_p1_location_id := p_user1_location_id;
    v_p2_location_id := p_user2_location_id;
  ELSE
    v_participant1_id := p_user2_id;
    v_participant2_id := p_user1_id;
    v_p1_family_member_id := p_user2_family_member_id;
    v_p2_family_member_id := p_user1_family_member_id;
    v_p1_location_id := p_user2_location_id;
    v_p2_location_id := p_user1_location_id;
  END IF;

  -- Validate p1 location: must exist in business_locations OR registered_business_locations
  IF v_p1_location_id IS NOT NULL THEN
    SELECT EXISTS(
      SELECT 1 FROM business_locations WHERE id = v_p1_location_id
      UNION ALL
      SELECT 1 FROM registered_business_locations WHERE id = v_p1_location_id
    ) INTO v_loc_exists;
    IF NOT v_loc_exists THEN
      v_p1_location_id := NULL;
    END IF;
  END IF;

  -- Validate p2 location: must exist in business_locations OR registered_business_locations
  IF v_p2_location_id IS NOT NULL THEN
    SELECT EXISTS(
      SELECT 1 FROM business_locations WHERE id = v_p2_location_id
      UNION ALL
      SELECT 1 FROM registered_business_locations WHERE id = v_p2_location_id
    ) INTO v_loc_exists;
    IF NOT v_loc_exists THEN
      v_p2_location_id := NULL;
    END IF;
  END IF;

  -- Look for existing conversation by core identity only
  SELECT id INTO v_conversation_id
  FROM conversations
  WHERE participant1_id = v_participant1_id
    AND participant2_id = v_participant2_id
    AND conversation_type = p_conversation_type
    AND reference_id = p_reference_id
  LIMIT 1;

  IF v_conversation_id IS NOT NULL THEN
    RETURN v_conversation_id;
  END IF;

  -- Insert new conversation
  INSERT INTO conversations (
    participant1_id,
    participant2_id,
    conversation_type,
    reference_id,
    participant1_family_member_id,
    participant2_family_member_id,
    participant1_location_id,
    participant2_location_id,
    ad_id
  )
  VALUES (
    v_participant1_id,
    v_participant2_id,
    p_conversation_type,
    p_reference_id,
    v_p1_family_member_id,
    v_p2_family_member_id,
    v_p1_location_id,
    v_p2_location_id,
    CASE WHEN p_conversation_type = 'classified_ad' THEN p_reference_id ELSE NULL END
  )
  ON CONFLICT ON CONSTRAINT unique_conversation_with_context
  DO NOTHING;

  -- Fetch id regardless of insert or conflict
  SELECT id INTO v_conversation_id
  FROM conversations
  WHERE participant1_id = v_participant1_id
    AND participant2_id = v_participant2_id
    AND conversation_type = p_conversation_type
    AND reference_id = p_reference_id
  LIMIT 1;

  RETURN v_conversation_id;
END;
$$;


-- ============================================================
-- FILE: 20260504144641_add_business_location_to_classified_ads_and_auctions.sql
-- ============================================================
/*
  # Add business location support to classified_ads and auctions

  ## Purpose
  Business users with multiple locations (sedi) need their classified ads and auctions
  to be associated with a specific location. This allows filtering so each sede sees
  only its own content, while the "all locations" view shows everything.

  ## Changes

  ### classified_ads
  - Add `business_location_id` (FK to business_locations) - for old business system
  - Add `registered_business_location_id` (FK to registered_business_locations) - for new system

  ### auctions
  - Add `business_location_id` (FK to business_locations)
  - Add `registered_business_location_id` (FK to registered_business_locations)

  ## Notes
  - Existing records remain with NULL location (treated as "all locations")
  - No destructive changes
*/

-- classified_ads: add business location columns
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'classified_ads' AND column_name = 'business_location_id'
  ) THEN
    ALTER TABLE classified_ads ADD COLUMN business_location_id uuid REFERENCES business_locations(id) ON DELETE SET NULL;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'classified_ads' AND column_name = 'registered_business_location_id'
  ) THEN
    ALTER TABLE classified_ads ADD COLUMN registered_business_location_id uuid REFERENCES registered_business_locations(id) ON DELETE SET NULL;
  END IF;
END $$;

-- auctions: add business location columns
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'auctions' AND column_name = 'business_location_id'
  ) THEN
    ALTER TABLE auctions ADD COLUMN business_location_id uuid REFERENCES business_locations(id) ON DELETE SET NULL;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'auctions' AND column_name = 'registered_business_location_id'
  ) THEN
    ALTER TABLE auctions ADD COLUMN registered_business_location_id uuid REFERENCES registered_business_locations(id) ON DELETE SET NULL;
  END IF;
END $$;

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_classified_ads_business_location_id ON classified_ads(business_location_id);
CREATE INDEX IF NOT EXISTS idx_classified_ads_registered_business_location_id ON classified_ads(registered_business_location_id);
CREATE INDEX IF NOT EXISTS idx_auctions_business_location_id ON auctions(business_location_id);
CREATE INDEX IF NOT EXISTS idx_auctions_registered_business_location_id ON auctions(registered_business_location_id);


-- ============================================================
-- FILE: 20260505150714_add_report_submitted_notification.sql
-- ============================================================
/*
  # Add notification when a report is submitted

  1. Changes
    - Adds a trigger on `reports` INSERT that sends a notification to the reporter
    - Notification type: 'report_submitted'
    - Also notifies all admin users about the new report

  2. Notes
    - The reporter receives confirmation that their report was received
    - Uses SECURITY DEFINER so the trigger can insert into notifications
*/

-- Function: notify reporter when they submit a report
CREATE OR REPLACE FUNCTION notify_report_submitted()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_entity_label text;
BEGIN
  v_entity_label := CASE NEW.reported_entity_type
    WHEN 'classified_ad' THEN 'annuncio'
    WHEN 'review' THEN 'recensione'
    WHEN 'business' THEN 'attività'
    WHEN 'auction' THEN 'asta'
    WHEN 'job_posting' THEN 'offerta di lavoro'
    ELSE 'contenuto'
  END;

  -- Notify the reporter that their report was received
  INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
  VALUES (
    NEW.reporter_id,
    NEW.family_member_id,
    'report_submitted',
    'Segnalazione inviata',
    'La tua segnalazione per questo ' || v_entity_label || ' è stata ricevuta e verrà esaminata dal nostro staff.',
    jsonb_build_object(
      'entity_type', NEW.reported_entity_type,
      'entity_id', NEW.reported_entity_id,
      'report_id', NEW.id
    )
  );

  RETURN NEW;
END;
$$;

-- Drop trigger if exists and recreate
DROP TRIGGER IF EXISTS trigger_notify_report_submitted ON reports;

CREATE TRIGGER trigger_notify_report_submitted
  AFTER INSERT ON reports
  FOR EACH ROW
  EXECUTE FUNCTION notify_report_submitted();


-- ============================================================
-- FILE: 20260505151931_fix_approve_auction_add_notification.sql
-- ============================================================
/*
  # Fix approve_auction: add notification to auction owner

  The approve_auction function was missing the INSERT into notifications.
  This migration recreates the function with the notification included.
*/

CREATE OR REPLACE FUNCTION approve_auction(
  p_auction_id uuid,
  p_admin_id uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_auction RECORD;
  points_to_award integer := 15;
  v_user_type text;
BEGIN
  SELECT * INTO v_auction FROM auctions WHERE id = p_auction_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Asta non trovata'; END IF;
  IF v_auction.approval_status != 'pending' THEN RAISE EXCEPTION 'L''asta e'' gia'' stata processata'; END IF;

  SELECT user_type INTO v_user_type FROM profiles WHERE id = v_auction.user_id;
  IF v_user_type = 'business' THEN points_to_award := 0; END IF;

  UPDATE auctions
  SET approval_status = 'approved',
      status = 'active',
      approved_by = p_admin_id,
      approved_at = now(),
      points_awarded = points_to_award
  WHERE id = p_auction_id;

  IF points_to_award > 0 THEN
    INSERT INTO user_activity (user_id, family_member_id, total_points, last_activity_at, created_at, updated_at)
    VALUES (v_auction.user_id, NULL, points_to_award, now(), now(), now())
    ON CONFLICT (user_id, family_member_id)
    DO UPDATE SET
      total_points = user_activity.total_points + points_to_award,
      last_activity_at = now(),
      updated_at = now();
  END IF;

  INSERT INTO activity_log (user_id, activity_type, title, description, points_earned, metadata)
  VALUES (
    p_admin_id,
    'auction_approved',
    'Asta approvata',
    v_auction.title,
    points_to_award,
    jsonb_build_object('auction_id', p_auction_id)
  );

  -- Notification to auction owner
  INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
  VALUES (
    v_auction.user_id,
    v_auction.family_member_id,
    'auction_approved',
    'Asta Approvata',
    CASE WHEN points_to_award > 0
      THEN 'La tua asta "' || v_auction.title || '" è stata approvata ed è ora visibile. Hai guadagnato ' || points_to_award || ' punti!'
      ELSE 'La tua asta "' || v_auction.title || '" è stata approvata ed è ora visibile a tutti gli utenti.'
    END,
    jsonb_build_object('auction_id', p_auction_id, 'points_awarded', points_to_award)
  );
END;
$$;


-- ============================================================
-- FILE: 20260505153034_fix_points_auctions_and_jobs_upsert.sql
-- ============================================================
/*
  # Fix points upsert for auctions and job postings

  ## Problem
  - approve_auction: used ON CONFLICT (user_id, family_member_id) but family_member_id
    was hardcoded NULL, so it never matched the correct unique index
    (user_activity_user_id_null_family_unique).
  - approve_job_posting: same issue — used wrong ON CONFLICT syntax.

  ## Fix
  Both functions now branch on whether family_member_id is NULL or not,
  using the correct unique index in each case, matching the pattern used
  by other working functions (approve_classified_ad, approve_review, etc.).
*/

-- ─── approve_auction ────────────────────────────────────────────────────────

CREATE OR REPLACE FUNCTION approve_auction(
  p_auction_id uuid,
  p_admin_id uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_auction       RECORD;
  points_to_award integer := 15;
  v_user_type     text;
BEGIN
  SELECT * INTO v_auction FROM auctions WHERE id = p_auction_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Asta non trovata'; END IF;
  IF v_auction.approval_status != 'pending' THEN RAISE EXCEPTION 'L''asta è già stata processata'; END IF;

  SELECT user_type INTO v_user_type FROM profiles WHERE id = v_auction.user_id;
  IF v_user_type = 'business' THEN points_to_award := 0; END IF;

  UPDATE auctions
  SET approval_status = 'approved',
      status          = 'active',
      approved_by     = p_admin_id,
      approved_at     = now(),
      points_awarded  = points_to_award
  WHERE id = p_auction_id;

  -- Award points using the correct unique index branch
  IF points_to_award > 0 THEN
    IF v_auction.family_member_id IS NOT NULL THEN
      INSERT INTO user_activity (user_id, family_member_id, total_points, last_activity_at, created_at, updated_at)
      VALUES (v_auction.user_id, v_auction.family_member_id, points_to_award, now(), now(), now())
      ON CONFLICT (user_id, family_member_id)
      DO UPDATE SET
        total_points     = user_activity.total_points + points_to_award,
        last_activity_at = now(),
        updated_at       = now();
    ELSE
      INSERT INTO user_activity (user_id, family_member_id, total_points, last_activity_at, created_at, updated_at)
      VALUES (v_auction.user_id, NULL, points_to_award, now(), now(), now())
      ON CONFLICT (user_id) WHERE family_member_id IS NULL
      DO UPDATE SET
        total_points     = user_activity.total_points + points_to_award,
        last_activity_at = now(),
        updated_at       = now();
    END IF;
  END IF;

  -- Activity log
  INSERT INTO activity_log (user_id, family_member_id, activity_type, title, description, points_earned, metadata, icon, color)
  VALUES (
    v_auction.user_id,
    v_auction.family_member_id,
    'auction_approved',
    'Asta Approvata',
    'La tua asta "' || v_auction.title || '" è stata approvata.',
    points_to_award,
    jsonb_build_object('auction_id', p_auction_id),
    'check-circle', 'green'
  );

  -- Notification to owner
  INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
  VALUES (
    v_auction.user_id,
    v_auction.family_member_id,
    'auction_approved',
    'Asta Approvata',
    CASE WHEN points_to_award > 0
      THEN 'La tua asta "' || v_auction.title || '" è stata approvata ed è ora visibile. Hai guadagnato ' || points_to_award || ' punti in classifica!'
      ELSE 'La tua asta "' || v_auction.title || '" è stata approvata ed è ora visibile a tutti gli utenti.'
    END,
    jsonb_build_object('auction_id', p_auction_id, 'points_awarded', points_to_award)
  );
END;
$$;

-- ─── approve_job_posting ────────────────────────────────────────────────────

CREATE OR REPLACE FUNCTION approve_job_posting(
  p_job_id   uuid,
  p_admin_id uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_job      RECORD;
  v_owner_id uuid;
  points_to_award integer := 10;
BEGIN
  SELECT jp.*, rb.owner_id AS rb_owner_id
  INTO v_job
  FROM job_postings jp
  LEFT JOIN registered_businesses rb ON rb.id = jp.registered_business_id
  WHERE jp.id = p_job_id;

  IF NOT FOUND THEN RAISE EXCEPTION 'Job posting not found'; END IF;

  -- Determine the real owner
  IF v_job.rb_owner_id IS NULL AND v_job.business_id IS NOT NULL THEN
    SELECT owner_id INTO v_owner_id FROM businesses WHERE id = v_job.business_id;
  ELSE
    v_owner_id := v_job.rb_owner_id;
  END IF;

  UPDATE job_postings
  SET approval_status = 'approved',
      status          = 'active',
      approved_at     = now(),
      approved_by     = p_admin_id
  WHERE id = p_job_id;

  IF v_owner_id IS NOT NULL THEN
    -- Award points using correct unique index branch (jobs have no family_member_id)
    INSERT INTO user_activity (user_id, family_member_id, total_points, job_postings_count, last_activity_at, created_at, updated_at)
    VALUES (v_owner_id, NULL, points_to_award, 1, now(), now(), now())
    ON CONFLICT (user_id) WHERE family_member_id IS NULL
    DO UPDATE SET
      total_points       = user_activity.total_points + points_to_award,
      job_postings_count = COALESCE(user_activity.job_postings_count, 0) + 1,
      last_activity_at   = now(),
      updated_at         = now();

    -- Activity log
    INSERT INTO activity_log (user_id, activity_type, title, description, points_earned, metadata, icon, color)
    VALUES (
      v_owner_id,
      'job_posting_approved',
      'Annuncio di Lavoro Approvato',
      'Il tuo annuncio di lavoro è stato approvato.',
      points_to_award,
      jsonb_build_object('job_id', p_job_id),
      'check-circle', 'green'
    );

    -- Notification
    INSERT INTO notifications (user_id, business_location_id, type, title, message, data)
    VALUES (
      v_owner_id,
      v_job.registered_business_location_id,
      'job_approved',
      'Annuncio di Lavoro Approvato',
      'Il tuo annuncio di lavoro è stato approvato ed è ora visibile. Hai guadagnato ' || points_to_award || ' punti in classifica!',
      jsonb_build_object('job_id', p_job_id, 'points_awarded', points_to_award)
    );
  END IF;
END;
$$;


-- ============================================================
-- FILE: 20260505153707_remove_points_auctions_and_jobs.sql
-- ============================================================
/*
  # Remove points for auctions and job postings

  Auctions and job postings do not award points to the leaderboard.
  Both approve_auction and approve_job_posting are updated to:
  - Skip all user_activity point updates
  - Skip activity_log point entries
  - Keep notifications (without points messaging)
*/

-- ─── approve_auction ────────────────────────────────────────────────────────

CREATE OR REPLACE FUNCTION approve_auction(
  p_auction_id uuid,
  p_admin_id uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_auction RECORD;
BEGIN
  SELECT * INTO v_auction FROM auctions WHERE id = p_auction_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Asta non trovata'; END IF;
  IF v_auction.approval_status != 'pending' THEN RAISE EXCEPTION 'L''asta è già stata processata'; END IF;

  UPDATE auctions
  SET approval_status = 'approved',
      status          = 'active',
      approved_by     = p_admin_id,
      approved_at     = now(),
      points_awarded  = 0
  WHERE id = p_auction_id;

  -- Notification to owner (no points)
  INSERT INTO notifications (user_id, family_member_id, type, title, message, data)
  VALUES (
    v_auction.user_id,
    v_auction.family_member_id,
    'auction_approved',
    'Asta Approvata',
    'La tua asta "' || v_auction.title || '" è stata approvata ed è ora visibile a tutti gli utenti.',
    jsonb_build_object('auction_id', p_auction_id)
  );
END;
$$;

-- ─── approve_job_posting ────────────────────────────────────────────────────

CREATE OR REPLACE FUNCTION approve_job_posting(
  p_job_id   uuid,
  p_admin_id uuid
)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_job      RECORD;
  v_owner_id uuid;
BEGIN
  SELECT jp.*, rb.owner_id AS rb_owner_id
  INTO v_job
  FROM job_postings jp
  LEFT JOIN registered_businesses rb ON rb.id = jp.registered_business_id
  WHERE jp.id = p_job_id;

  IF NOT FOUND THEN RAISE EXCEPTION 'Job posting not found'; END IF;

  IF v_job.rb_owner_id IS NULL AND v_job.business_id IS NOT NULL THEN
    SELECT owner_id INTO v_owner_id FROM businesses WHERE id = v_job.business_id;
  ELSE
    v_owner_id := v_job.rb_owner_id;
  END IF;

  UPDATE job_postings
  SET approval_status = 'approved',
      status          = 'active',
      approved_at     = now(),
      approved_by     = p_admin_id
  WHERE id = p_job_id;

  IF v_owner_id IS NOT NULL THEN
    -- Notification (no points)
    INSERT INTO notifications (user_id, business_location_id, type, title, message, data)
    VALUES (
      v_owner_id,
      v_job.registered_business_location_id,
      'job_approved',
      'Annuncio di Lavoro Approvato',
      'Il tuo annuncio di lavoro è stato approvato ed è ora visibile a tutti gli utenti.',
      jsonb_build_object('job_id', p_job_id)
    );
  END IF;
END;
$$;


